// ─── Stat Detail Overlay ─────────────────────────────────────────────────────
function showStatDetail(cfg) {
  window.dispatchEvent(new CustomEvent('xa-stat-detail', { detail: cfg }));
}
function StatDetailOverlay({ data, onClose }) {
  if (!data) return null;
  return ReactDOM.createPortal(
    <div onClick={e=>{ if(e.target===e.currentTarget) onClose(); }} style={{ position:'fixed', inset:0, background:'rgba(28,37,81,0.45)', zIndex:2000, display:'flex', alignItems:'center', justifyContent:'center', padding:20, fontFamily:'Poppins,sans-serif' }}>
      <div style={{ background:'#fff', borderRadius:16, width:'100%', maxWidth:480, maxHeight:'82vh', display:'flex', flexDirection:'column', overflow:'hidden', boxShadow:'0 24px 64px rgba(28,37,81,0.22)' }}>
        <div style={{ padding:'18px 22px 14px', borderBottom:'1px solid #EAECF4', display:'flex', justifyContent:'space-between', alignItems:'flex-start' }}>
          <div>
            <div style={{ fontSize:12, color:'#8b90a7', fontWeight:600, marginBottom:4 }}>{data.label}</div>
            <div style={{ fontSize:34, fontWeight:800, color:data.color||'#1C2551', lineHeight:1 }}>{data.value}</div>
            {data.sub && <div style={{ fontSize:12, color:'#8b90a7', marginTop:4 }}>{data.sub}</div>}
          </div>
          <button onClick={onClose} style={{ width:28, height:28, border:'1px solid #EAECF4', borderRadius:'50%', background:'#fff', cursor:'pointer', fontSize:14, display:'flex', alignItems:'center', justifyContent:'center', color:'#8b90a7', flexShrink:0 }}>✕</button>
        </div>
        <div style={{ flex:1, overflowY:'auto', padding:'16px 22px', display:'flex', flexDirection:'column', gap:18 }}>
          {(data.sections||[]).map((sec,si) => (
            <div key={si}>
              <div style={{ fontSize:11, fontWeight:700, color:'#8b90a7', letterSpacing:0.5, marginBottom:10 }}>{sec.title}</div>
              <div style={{ display:'flex', flexDirection:'column', gap:8 }}>
                {(sec.rows||[]).map((row,ri) => (
                  <div key={ri} style={{ display:'flex', alignItems:'center', gap:10 }}>
                    {row.dot && <div style={{ width:8, height:8, borderRadius:'50%', background:row.dot, flexShrink:0 }}></div>}
                    <span style={{ flex:1, fontSize:13, color:'#1C2551' }}>{row.label}</span>
                    <span style={{ fontSize:13, fontWeight:700, color:row.color||data.color||'#1C2551' }}>{row.value}</span>
                    {row.bar!=null && (
                      <div style={{ width:80, height:5, background:'#F0F1F7', borderRadius:99, flexShrink:0 }}>
                        <div style={{ height:'100%', width:`${row.bar}%`, background:row.color||data.color||'#EF4E24', borderRadius:99 }}></div>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>,
    document.body
  );
}

