function Sidebar({ persona, activePage, onNavigate, program }) {
  const config = NAV_CONFIG[persona];
  return (
    <aside style={sidebarStyles.sidebar}>
      <div style={sidebarStyles.logoArea}>
        <div style={sidebarStyles.logoMark}>
          <img src={window.__resources?.xaLogo||"./xa-logo.png"} alt="XA" style={{ width:28, height:28, objectFit:'contain' }} />
        </div>
        <div>
          <div style={sidebarStyles.logoText}>XA LMS</div>
          <div style={sidebarStyles.logoSub}>by fourward</div>
        </div>
      </div>
      {(persona === 'participant' || persona === 'programManager') && (
        <div style={sidebarStyles.phaseBox}>
          <div style={sidebarStyles.phaseLabel}>Current Phase</div>
          <div style={sidebarStyles.phaseValue}>{persona==='participant'&&program ? program.currentPhaseLabel : 'Phase 3: Classroom'}</div>
          <div style={sidebarStyles.phaseBar}>
            <div style={{ ...sidebarStyles.phaseBarFill, width:(persona==='participant'&&program ? program.overallPct : 45)+'%', background:persona==='participant'&&program?program.color:'#EF4E24' }}></div>
          </div>
          <div style={sidebarStyles.phaseProgress}>{persona==='participant'&&program ? program.phasesComplete+' of '+program.phasesTotal+' phases complete' : '3 of 7 phases complete'}</div>
        </div>
      )}
      <nav style={sidebarStyles.nav}>
        {config.items.map(item => (
          <button key={item.id} onClick={() => onNavigate(item.id)}
            style={{ ...sidebarStyles.navItem, ...(activePage === item.id ? sidebarStyles.navItemActive : {}) }}>
            <span style={sidebarStyles.navIcon}>{item.icon}</span>
            <span>{item.label}</span>
            {activePage === item.id && <span style={sidebarStyles.activeBar}></span>}
          </button>
        ))}
      </nav>
    </aside>
  );
}

function Header({ title, subtitle, persona, onProfileClick, orgFilter, onOrgChange, programs, selectedProg, onProgChange, onSettingsClick }) {
  const [notifOpen, setNotifOpen] = React.useState(false);
  const ORGS = ['All Orgs','Mahindra Group','Tata Sons','HDFC Bank','Infosys Ltd.','Wipro Ltd.'];
  return (
    <header style={sidebarStyles.header}>
      <div style={{ display:'flex', alignItems:'flex-end', gap:16 }}>
        <div>
          <div style={sidebarStyles.headerTitle}>{title}</div>
          {(persona==='participant'||persona==='faculty')&&selectedProg&&programs ? <ProgramSwitcherDropdown programs={programs} selectedProg={selectedProg} onProgChange={onProgChange} /> : subtitle ? <div style={sidebarStyles.headerSub}>{subtitle}</div> : null}
        </div>
        {persona === 'superAdmin' && (
          <div style={{ display:'flex', alignItems:'center', gap:6, paddingBottom:2 }}>
            <span style={{ fontSize:11, color:'#8b90a7', fontWeight:600 }}>Org:</span>
            <CustomSelect
              value={orgFilter||'All Orgs'}
              onChange={v=>onOrgChange&&onOrgChange(v)}
              options={['All Orgs','Mahindra Group','Tata Sons','HDFC Bank','Infosys Ltd.','Wipro Ltd.']}
              style={{ minWidth:140 }}
            />
          </div>
        )}
      </div>
      <div style={sidebarStyles.headerRight}>
        <button style={sidebarStyles.iconBtn} onClick={() => setNotifOpen(!notifOpen)}>
          <span>🔔</span>
          <span style={sidebarStyles.notifBadge}>3</span>
        </button>
        {notifOpen && (
          <div style={sidebarStyles.notifDropdown}>
            {['Pre-work deadline tomorrow','New feedback received','Coaching session at 3PM'].map((n,i) => (
              <div key={i} style={sidebarStyles.notifItem}>{n}</div>
            ))}
          </div>
        )}
        <button onClick={onSettingsClick} style={{...sidebarStyles.iconBtn}}>⚙</button>
        <button onClick={onProfileClick} style={{ display:'flex', alignItems:'center', gap:8, border:'1px solid #EAECF4', borderRadius:22, padding:'4px 14px 4px 4px', background:'#fff', cursor:'pointer', fontFamily:'Poppins,sans-serif', flexShrink:0 }}>
          <div style={{ width:28, height:28, borderRadius:'50%', background:PERSONA_META[persona].color, color:'#fff', fontWeight:700, fontSize:11, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0, overflow:'hidden' }}>
            {localStorage.getItem('xa_photo_'+persona) ? <img src={localStorage.getItem('xa_photo_'+persona)} alt="" style={{ width:'100%', height:'100%', objectFit:'cover' }} /> : NAV_CONFIG[persona].avatar}
          </div>
          <span style={{ fontSize:12, fontWeight:600, color:'#1C2551', whiteSpace:'nowrap' }}>{NAV_CONFIG[persona].name}</span>
        </button>
      </div>
    </header>
  );
}

// ─── Shared Participant UI ────────────────────────────────────────────────────
function Card({ children, style, onClick }) {
  return <div onClick={onClick} style={{ background:'#fff', borderRadius:12, boxShadow:'0 1px 4px rgba(28,37,81,0.07)', border:'1px solid #EAECF4', padding:20, ...style }}>{children}</div>;
}
function Badge({ label, color='#EF4E24', bg }) {
  return <span style={{ background:bg||`${color}14`, color, fontSize:10, fontWeight:700, borderRadius:20, padding:'3px 9px', letterSpacing:0.3 }}>{label}</span>;
}
function ProgressBar({ pct, color='#EF4E24', height=6 }) {
  return (
    <div style={{ height, background:'#F0F1F7', borderRadius:99 }}>
      <div style={{ height:'100%', width:`${pct}%`, background:color, borderRadius:99, transition:'width 0.4s' }}></div>
    </div>
  );
}
function StatCard({ label, value, sub, icon, accent, detail }) {
  return (
    <Card style={{ flex:1, cursor:detail?'pointer':'default' }} onClick={detail?()=>showStatDetail({label,value,sub,color:accent,...detail}):undefined}>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start' }}>
        <div>
          <div style={{ fontSize:11, color:'#8b90a7', marginBottom:6 }}>{label}</div>
          <div style={{ fontSize:26, fontWeight:800, color:accent||'#1C2551' }}>{value}</div>
          {sub && <div style={{ fontSize:11, color:'#8b90a7', marginTop:3 }}>{sub}</div>}
        </div>
        <div style={{ display:'flex', flexDirection:'column', alignItems:'flex-end', gap:4 }}>
          <div style={{ fontSize:22, opacity:0.7 }}>{icon}</div>
          {detail && <span style={{ fontSize:9, color:'#8b90a7', fontWeight:600 }}>TAP FOR DETAILS</span>}
        </div>
      </div>
    </Card>
  );
}

