function SettingsPanel({ persona, onClose }) {
  const [tab, setTab] = React.useState('account');
  const [saved, setSaved] = React.useState(false);
  const [notifs, setNotifs] = React.useState({ email:true, push:true, sms:false, deadlines:true, feedback:true, sessions:true, reports:false });
  const [platform, setPlatform] = React.useState({ maintenance:false, sessionTimeout:30, mfaRequired:false, passwordExpiry:90 });
  const nav = NAV_CONFIG[persona];
  const isSA = persona === 'superAdmin';
  const isPM = persona === 'programManager';
  const TABS = [
    { id:'account',       label:'My Account',    icon:'◎' },
    { id:'notifications', label:'Notifications', icon:'🔔' },
    ...(isSA ? [{ id:'platform', label:'Platform', icon:'◈' },{ id:'security', label:'Security', icon:'◆' },{ id:'api', label:'API & Keys', icon:'✦' },{ id:'features', label:'Feature Flags', icon:'⬡' },{ id:'storage', label:'Storage', icon:'▦' },{ id:'localization', label:'Localization', icon:'◎' }] : []),
    ...((isSA || isPM) ? [{ id:'brandkit', label:'Brand Kit', icon:'🎨' }] : []),
    { id:'appearance',    label:'Appearance',    icon:'◇' },
  ];
  function save() { setSaved(true); setTimeout(()=>setSaved(false), 2200); }
  return ReactDOM.createPortal(
    <div onClick={e=>{if(e.target===e.currentTarget)onClose();}} style={{position:'fixed',inset:0,background:'rgba(28,37,81,0.22)',zIndex:500,display:'flex',justifyContent:'flex-end',fontFamily:'Poppins,sans-serif'}}>
      <div style={{width:'min(580px,100vw)',height:'100%',background:'#fff',boxShadow:'-8px 0 40px rgba(28,37,81,0.14)',display:'flex',flexDirection:'column',overflow:'hidden'}}>
        <div style={{padding:'18px 24px',borderBottom:'1px solid #EAECF4',display:'flex',justifyContent:'space-between',alignItems:'center',flexShrink:0}}>
          <div style={{fontSize:16,fontWeight:700,color:'#1C2551'}}>Settings</div>
          <button onClick={onClose} style={{width:28,height:28,border:'1px solid #EAECF4',borderRadius:'50%',background:'#fff',cursor:'pointer',fontSize:14,color:'#8b90a7',display:'flex',alignItems:'center',justifyContent:'center',fontFamily:'Poppins,sans-serif'}}>✕</button>
        </div>
        <div style={{flex:1,display:'flex',overflow:'hidden'}}>
          <div style={{width:152,borderRight:'1px solid #EAECF4',padding:'12px 8px',flexShrink:0,overflowY:'auto',background:'#FAFBFC'}}>
            {TABS.map(t=>(
              <button key={t.id} onClick={()=>setTab(t.id)} style={{display:'flex',alignItems:'center',gap:9,padding:'9px 12px',width:'100%',border:'none',background:tab===t.id?'rgba(239,78,36,0.08)':'transparent',borderRadius:8,cursor:'pointer',fontFamily:'Poppins,sans-serif',marginBottom:2,textAlign:'left'}}>
                <span style={{fontSize:13,color:tab===t.id?'#EF4E24':'#8b90a7',width:18,textAlign:'center',flexShrink:0}}>{t.icon}</span>
                <span style={{fontSize:12,fontWeight:tab===t.id?700:400,color:tab===t.id?'#EF4E24':'#8b90a7',whiteSpace:'nowrap'}}>{t.label}</span>
              </button>
            ))}
          </div>
          <div style={{flex:1,overflowY:'auto',padding:'20px',display:'flex',flexDirection:'column',gap:14}}>
            {tab==='account'       && <AccountTab persona={persona} nav={nav} />}
            {tab==='notifications' && <NotificationsTab notifs={notifs} setNotifs={setNotifs} />}
            {tab==='platform'      && isSA && <PlatformTab platform={platform} setPlatform={setPlatform} />}
            {tab==='security'      && isSA && <SecurityTab />}
            {tab==='api'           && isSA && <ApiKeysTab />}
            {tab==='brandkit'     && (isSA||isPM) && <BrandKitTab />}
            {tab==='features'     && isSA && <FeaturesTab />}
            {tab==='storage'      && isSA && <StorageTab />}
            {tab==='localization' && isSA && <LocalizationTab />}
            {tab==='appearance'    && <AppearanceTab />}
          </div>
        </div>
        <div style={{padding:'14px 24px',borderTop:'1px solid #EAECF4',display:'flex',justifyContent:'space-between',alignItems:'center',flexShrink:0}}>
          <div style={{display:'flex',gap:10}}>
            <button onClick={onClose} style={{padding:'9px 20px',border:'1px solid #EAECF4',borderRadius:8,background:'#fff',cursor:'pointer',fontSize:12,fontWeight:600,color:'#8b90a7',fontFamily:'Poppins,sans-serif'}}>Cancel</button>
            <button onClick={save} style={{padding:'9px 22px',border:'none',borderRadius:8,background:saved?'#22c55e':'#EF4E24',cursor:'pointer',fontSize:12,fontWeight:700,color:'#fff',fontFamily:'Poppins,sans-serif',transition:'background 0.2s',minWidth:120}}>
              {saved ? '✓ Saved!' : 'Save Changes'}
            </button>
          </div>
        </div>
      </div>
    </div>,
    document.body
  );
}

function ProgramSwitcherDropdown({ programs, selectedProg, onProgChange }) {
  const [open, setOpen] = React.useState(false);
  const statusColors = { Active:'#22c55e', Completed:'#6B73BF' };
  React.useEffect(() => {
    if (!open) return;
    function handler(e) { if (!e.target.closest('[data-prog-switcher]')) setOpen(false); }
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, [open]);
  return (
    <div style={{ position:'relative' }} data-prog-switcher="1">
      <button onClick={() => setOpen(o=>!o)} style={{ display:'flex', alignItems:'center', gap:6, background:'none', border:'none', cursor:'pointer', padding:'2px 0', fontFamily:'Poppins,sans-serif' }}>
        <span style={{ width:8, height:8, borderRadius:'50%', background:statusColors[selectedProg.status]||'#EF4E24', display:'inline-block', flexShrink:0 }}></span>
        <span style={{ fontSize:12, color:'#8b90a7', fontWeight:500, maxWidth:280, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{selectedProg.name} · {selectedProg.currentPhaseLabel}</span>
        <span style={{ fontSize:9, color:'#8b90a7' }}>▼</span>
      </button>
      {open && (
        <div style={{ position:'absolute', top:'calc(100% + 6px)', left:0, background:'#fff', borderRadius:12, boxShadow:'0 8px 32px rgba(28,37,81,0.14)', border:'1px solid #EAECF4', minWidth:300, zIndex:300, overflow:'hidden' }}>
          <div style={{ padding:'10px 14px', fontSize:10, fontWeight:700, color:'#8b90a7', letterSpacing:0.5, borderBottom:'1px solid #EAECF4' }}>MY ENROLLED PROGRAMS</div>
          {programs.map(p => (
            <button key={p.id} onClick={() => { onProgChange(p.id); setOpen(false); }} style={{ display:'flex', alignItems:'center', gap:12, padding:'11px 14px', width:'100%', border:'none', background:p.id===selectedProg.id?'rgba(239,78,36,0.04)':'#fff', cursor:'pointer', fontFamily:'Poppins,sans-serif', borderBottom:'1px solid #F5F7FB' }}>
              <div style={{ width:10, height:10, borderRadius:'50%', background:p.color, flexShrink:0 }}></div>
              <div style={{ flex:1, textAlign:'left' }}>
                <div style={{ fontSize:12, fontWeight:600, color:'#1C2551' }}>{p.name}</div>
                <div style={{ display:'flex', alignItems:'center', gap:6, marginTop:3 }}>
                  <span style={{ fontSize:10, color:'#8b90a7' }}>{p.currentPhaseLabel}</span>
                  <div style={{ height:4, width:60, background:'#F0F1F7', borderRadius:2 }}>
                    <div style={{ height:'100%', width:p.overallPct+'%', background:p.color, borderRadius:2 }}></div>
                  </div>
                  <span style={{ fontSize:10, color:p.color, fontWeight:700 }}>{p.overallPct}%</span>
                </div>
              </div>
              {p.id===selectedProg.id && <span style={{ color:'#EF4E24', fontSize:14 }}>✓</span>}
              <span style={{ fontSize:10, background:p.status==='Completed'?'rgba(107,115,191,0.12)':'rgba(34,197,94,0.1)', color:p.status==='Completed'?'#6B73BF':'#22c55e', borderRadius:10, padding:'2px 8px', fontWeight:700, flexShrink:0 }}>{p.status}</span>
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

// ─── Mobile Program Switcher ──────────────────────────────────────────────────
function MobileProgramSwitcher({ programs, selectedProgId, onProgChange }) {
  return (
    <div style={{ overflowX:'auto', display:'flex', gap:10, paddingBottom:4, scrollbarWidth:'none' }}>
      {programs.map(p => (
        <button key={p.id} onClick={() => onProgChange(p.id)} style={{ flexShrink:0, display:'flex', flexDirection:'column', gap:4, padding:'10px 12px', border:'1.5px solid '+(p.id===selectedProgId?p.color:'#EAECF4'), borderRadius:12, background:p.id===selectedProgId?p.color+'12':'#fff', cursor:'pointer', textAlign:'left', fontFamily:'Poppins,sans-serif', minWidth:170 }}>
          <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between' }}>
            <span style={{ fontSize:9, fontWeight:700, color:p.id===selectedProgId?p.color:'#8b90a7', letterSpacing:0.5 }}>{p.status.toUpperCase()}</span>
            {p.id===selectedProgId && <span style={{ width:6, height:6, borderRadius:'50%', background:p.color, display:'inline-block' }}></span>}
          </div>
          <div style={{ fontSize:12, fontWeight:700, color:'#1C2551', lineHeight:1.3 }}>{p.name}</div>
          <div style={{ fontSize:10, color:'#8b90a7' }}>{p.currentPhaseLabel}</div>
          <div style={{ height:3, background:'#E0E3EF', borderRadius:2, marginTop:2 }}>
            <div style={{ height:'100%', width:p.overallPct+'%', background:p.color, borderRadius:2 }}></div>
          </div>
        </button>
      ))}
    </div>
  );
}

// ─── Participant Views ────────────────────────────────────────────────────────
function ParticipantDashboard({ prog }) {
  if (!prog) prog = PARTICIPANT_PROGRAMS[0];
  const phases = prog.phases;
  const activities = prog.activities;
  const stats = prog.stats;
  return (
    <div style={pStyles.page}>
      <div style={pStyles.aiBanner}>
        <span style={{ fontSize:16, marginRight:10 }}>✦</span>
        <div>
          <div style={{ fontWeight:700, fontSize:13, marginBottom:2 }}>AI Daily Focus</div>
          <div style={{ fontSize:12, opacity:0.85 }}>{prog.aiInsight}</div>
        </div>
      </div>
      <div style={pStyles.statsRow}>
        <StatCard label="Program Progress" value={stats.progress.value} sub={stats.progress.sub} icon="◈" accent={prog.color} detail={{ sections:[{title:'PHASE BREAKDOWN',rows:[{label:'Pre-Enrolment',value:'Done',dot:'#22c55e'},{label:'Orientation',value:'Done',dot:'#22c55e'},{label:'Pre-Work',value:'Done',dot:'#22c55e'},{label:'Classroom',value:'In Progress',dot:'#EF4E24'},{label:'Post Classroom',value:'Locked',dot:'#D0D3E0'},{label:'Group Coaching',value:'Locked',dot:'#D0D3E0'},{label:'Capstone',value:'Locked',dot:'#D0D3E0'}]},{title:'COMPLETION STATS',rows:[{label:'Activities Completed',value:'18 / 42',bar:42,color:'#1C2551'},{label:'Assessments Done',value:'3 / 7',bar:43,color:'#EF4E24'},{label:'Coaching Sessions',value:'3 / 6',bar:50,color:'#6B73BF'}]}]}} />
        <StatCard label="Activities Completed" value={stats.activities.value} sub={stats.activities.sub} icon="✦" accent={prog.color} detail={{ sections:[{title:'BY TYPE',rows:[{label:'Video Modules',value:'6',bar:60,color:'#EF4E24'},{label:'PDF / Articles',value:'4',bar:40,color:'#1C2551'},{label:'Case Studies',value:'3',bar:30,color:'#6B73BF'},{label:'Assessments',value:'3',bar:30,color:'#22c55e'},{label:'Reflection Journals',value:'2',bar:20,color:'#EF4E24'}]},{title:'RECENT ACTIVITY',rows:[{label:'Reflection Journal – Day 1',value:'Apr 29'},{label:'Pre-Work Knowledge Check',value:'Apr 27'},{label:'Leading Through Uncertainty',value:'Apr 25'}]}]}} />
        <StatCard label="Engagement Streak" value={stats.streak.value} sub={stats.streak.sub} icon="🔥" accent={prog.color} detail={{ sections:[{title:'DAILY ACTIVITY (LAST 7 DAYS)',rows:[{label:'Monday',value:'Active',dot:'#22c55e'},{label:'Tuesday',value:'Active',dot:'#22c55e'},{label:'Wednesday',value:'Active',dot:'#22c55e'},{label:'Thursday',value:'Active',dot:'#22c55e'},{label:'Friday',value:'Active',dot:'#22c55e'},{label:'Saturday',value:'Missed',dot:'#D0D3E0'},{label:'Sunday',value:'Missed',dot:'#D0D3E0'}]},{title:'STREAK STATS',rows:[{label:'Current Streak',value:'5 days'},{label:'Longest Streak',value:'9 days'},{label:'Total Active Days',value:'22'},{label:'Avg Daily Time',value:'42 min'}]}]}} />
        <StatCard label="Leaderboard Rank" value={stats.rank.value} sub={stats.rank.sub} icon="◆" accent="#1C2551" detail={{ sections:[{title:'TOP 5 PARTICIPANTS',rows:[{label:'1. Arjun Mehta',value:'2,840 pts',bar:100,color:'#EF4E24'},{label:'2. Sneha Pillai',value:'2,710 pts',bar:95,color:'#1C2551'},{label:'3. Rohit Gupta',value:'2,690 pts',bar:94,color:'#6B73BF'},{label:'4. Meera Nair',value:'2,540 pts',bar:89,color:'#1C2551'},{label:'5. Vivek Sharma',value:'2,480 pts',bar:87,color:'#1C2551'}]},{title:'YOUR POSITION',rows:[{label:'Your Rank',value:'#7 of 32'},{label:'Your Points',value:'2,290 pts'},{label:'Points to #6',value:'70 pts needed'},{label:'Points to #5',value:'190 pts needed'}]}]}} />
      </div>
      <Card>
        <div style={{ fontWeight:700, fontSize:14, color:'#1C2551', marginBottom:16 }}>Learning Journey Timeline</div>
        <div style={{ display:'flex', alignItems:'center', gap:0, overflowX:'auto' }}>
          {phases.map((p,i) => (
            <React.Fragment key={i}>
              <div style={{ display:'flex', flexDirection:'column', alignItems:'center', minWidth:90 }}>
                <div style={{ width:32, height:32, borderRadius:'50%', border:'2px solid', borderColor:p.status==='done'?'#1C2551':p.status==='active'?'#EF4E24':'#D0D3E0', background:p.status==='done'?'#1C2551':p.status==='active'?'#EF4E24':'#F5F7FB', color:p.status==='locked'?'#aaa':'#fff', display:'flex', alignItems:'center', justifyContent:'center', fontSize:13, fontWeight:700, zIndex:1 }}>
                  {p.status==='done'?'✓':p.status==='active'?'●':i}
                </div>
                <div style={{ fontSize:10, color:p.status==='active'?'#EF4E24':'#8b90a7', marginTop:6, textAlign:'center', fontWeight:p.status==='active'?700:400, maxWidth:80 }}>{p.label}</div>
              </div>
              {i < phases.length-1 && <div style={{ flex:1, height:2, background:i<3?'#1C2551':'#E0E3EF', minWidth:16, marginBottom:22 }}></div>}
            </React.Fragment>
          ))}
        </div>
      </Card>
      <div style={{ display:'grid', gridTemplateColumns:'1fr 340px', gap:16 }}>
        <Card>
          <div style={{ fontWeight:700, fontSize:14, color:'#1C2551', marginBottom:14 }}>Upcoming Activities</div>
          <div style={{ display:'flex', flexDirection:'column', gap:10 }}>
            {activities.map((a,i) => (
              <div key={i} style={{ display:'flex', alignItems:'center', gap:14, padding:'12px 14px', borderRadius:9, background:a.urgent?'rgba(239,78,36,0.04)':'#F9FAFB', border:`1px solid ${a.urgent?'rgba(239,78,36,0.15)':'#EAECF4'}` }}>
                <div style={{ flex:1 }}>
                  <div style={{ display:'flex', alignItems:'center', gap:8, marginBottom:4 }}>
                    <span style={{ fontSize:13, fontWeight:600, color:'#1C2551' }}>{a.title}</span>
                    {a.urgent && <Badge label="Due Today" />}
                  </div>
                  <div style={{ display:'flex', gap:8, alignItems:'center' }}>
                    <Badge label={a.type} color="#1C2551" />
                    <span style={{ fontSize:11, color:'#8b90a7' }}>Due: {a.due}</span>
                  </div>
                  {a.pct > 0 && a.pct < 100 && <div style={{ marginTop:8 }}><ProgressBar pct={a.pct} /></div>}
                </div>
                <button style={pStyles.actionBtn}>{a.pct===100?'Review':'Continue →'}</button>
              </div>
            ))}
          </div>
        </Card>
        <Card>
          <div style={{ fontWeight:700, fontSize:14, color:'#1C2551', marginBottom:14 }}>Learning Contract</div>
          {(prog.goals||[]).map((g,i) => (
            <div key={i} style={{ marginBottom:14 }}>
              <div style={{ display:'flex', justifyContent:'space-between', marginBottom:4 }}>
                <div style={{ fontSize:12, color:'#1C2551', fontWeight:500 }}>{g.label}</div>
                <span style={{ fontSize:11, color:g.color, fontWeight:700 }}>{g.pct}%</span>
              </div>
              <ProgressBar pct={g.pct} color={g.color} />
            </div>
          ))}
          <div style={{ marginTop:16, padding:'10px 14px', background:'#F5F7FB', borderRadius:8, fontSize:11, color:'#8b90a7' }}>
            Next check-in: <strong style={{ color:'#1C2551' }}>May 7, 2026</strong>
          </div>
        </Card>
      </div>
    </div>
  );
}

function ParticipantPrework({ prog }) {
  if (!prog) prog = PARTICIPANT_PROGRAMS[0];
  const [selected, setSelected] = React.useState(null);
  const modules = prog.prework;
  return (
    <div style={pStyles.page}>
      <div style={{ display:'grid', gridTemplateColumns:'1fr 300px', gap:16 }}>
        <div style={{ display:'flex', flexDirection:'column', gap:12 }}>
          {modules.map((m,i) => (
            <Card key={i} style={{ cursor:'pointer', border:selected===i?'1.5px solid #EF4E24':'1px solid #EAECF4' }} onClick={() => setSelected(i===selected?null:i)}>
              <div style={{ display:'flex', alignItems:'center', gap:14 }}>
                <div style={{ width:44, height:44, borderRadius:10, background:m.pct===100?'rgba(28,37,81,0.06)':'rgba(239,78,36,0.08)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:18 }}>
                  {m.type==='Video'?'▶':m.type==='PDF'?'📄':m.type==='Case Study'?'📋':m.type==='Assessment'?'✦':'📖'}
                </div>
                <div style={{ flex:1 }}>
                  <div style={{ fontWeight:600, fontSize:13, color:'#1C2551', marginBottom:4 }}>{m.title}</div>
                  <div style={{ display:'flex', gap:6, flexWrap:'wrap' }}>
                    <Badge label={m.type} color="#1C2551" />
                    <span style={{ fontSize:11, color:'#8b90a7' }}>⏱ {m.duration}</span>
                    {m.tags.map(t => <Badge key={t} label={t} color="#6B73BF" />)}
                  </div>
                  {m.pct > 0 && <div style={{ marginTop:8 }}><ProgressBar pct={m.pct} /></div>}
                </div>
                <div>
                  {m.pct===100 ? <span style={{ color:'#22c55e', fontWeight:700 }}>✓ Done</span>
                  : <button style={pStyles.actionBtn}>{m.pct>0?'Resume':'Start'}</button>}
                </div>
              </div>
            </Card>
          ))}
        </div>
        <div style={{ display:'flex', flexDirection:'column', gap:12 }}>
          <Card>
            <div style={{ fontWeight:700, fontSize:13, color:'#1C2551', marginBottom:12 }}>Module Progress</div>
            <div style={{ fontSize:32, fontWeight:800, color:'#EF4E24', marginBottom:4 }}>{prog.prework.filter(m=>m.pct===100).length}/{prog.prework.length}</div>
            <div style={{ fontSize:11, color:'#8b90a7', marginBottom:12 }}>Modules completed</div>
            <ProgressBar pct={Math.round(prog.prework.filter(m=>m.pct===100).length/prog.prework.length*100)} color={prog.color} />
            <div style={{ marginTop:16, fontSize:12, color:'#8b90a7' }}>Estimated remaining: <strong style={{ color:'#1C2551' }}>1h 50m</strong></div>
          </Card>
          <Card style={{ background:'rgba(239,78,36,0.03)', border:'1px solid rgba(239,78,36,0.15)' }}>
            <div style={{ fontSize:11, fontWeight:700, color:'#EF4E24', marginBottom:8 }}>✦ AI Recommendation</div>
            <div style={{ fontSize:12, color:'#1C2551', lineHeight:1.6 }}>Complete the HBR Case Study before the classroom session — it directly connects to Module 2 facilitation on Day 2.</div>
          </Card>
          <Card>
            <div style={{ fontWeight:700, fontSize:13, color:'#1C2551', marginBottom:10 }}>Note-Taking</div>
            <textarea style={{ width:'100%', height:100, border:'1px solid #EAECF4', borderRadius:8, padding:10, fontSize:12, fontFamily:'Poppins, sans-serif', resize:'none', boxSizing:'border-box' }} placeholder="Capture your key insights..."></textarea>
            <button style={{ ...pStyles.actionBtn, marginTop:8, width:'100%', justifyContent:'center' }}>Save Note</button>
          </Card>
        </div>
      </div>
    </div>
  );
}

