const DS_PHASE_TYPES = [
  { type:'pre-enrolment',    label:'Pre-Enrolment',     color:'#6B73BF', icon:'◎', defaultDays:14 },
  { type:'orientation',      label:'Orientation',        color:'#1C2551', icon:'◈', defaultDays:7  },
  { type:'module-virtual',   label:'Module · Virtual',   color:'#EF4E24', icon:'⬡', defaultDays:3, deliveryMode:'virtual'   },
  { type:'module-in-person', label:'Module · In-Person', color:'#1C2551', icon:'⬡', defaultDays:3, deliveryMode:'in-person' },
  { type:'coaching',         label:'Group Coaching',     color:'#EF4E24', icon:'○', defaultDays:42 },
  { type:'capstone',         label:'Capstone',           color:'#1C2551', icon:'▲', defaultDays:5  },
  { type:'post-program',     label:'Post Program',       color:'#22c55e', icon:'◆', defaultDays:60 },
];

const DS_ELEMENT_TYPES = [
  { type:'quiz',        label:'Quiz',               icon:'✦', color:'#6B73BF' },
  { type:'elearning',   label:'eLearning Module',   icon:'▤', color:'#1C2551' },
  { type:'assessment',  label:'Assessment',         icon:'◎', color:'#EF4E24' },
  { type:'video',       label:'Video',              icon:'▶', color:'#1C2551' },
  { type:'case-study',  label:'Case Study',         icon:'◈', color:'#6B73BF' },
  { type:'360',         label:'360° Feedback',      icon:'◇', color:'#EF4E24' },
  { type:'l1-feedback', label:'L1 · Reaction',      icon:'≡', color:'#22c55e' },
  { type:'l2-feedback', label:'L2 · Learning',      icon:'≡', color:'#22c55e' },
  { type:'l3-feedback', label:'L3 · Behaviour',     icon:'≡', color:'#22c55e' },
  { type:'l4-feedback', label:'L4 · Impact',        icon:'≡', color:'#22c55e' },
  { type:'survey',      label:'Survey',             icon:'≡', color:'#8b90a7' },
  { type:'journal',     label:'Reflection Journal', icon:'◈', color:'#8b90a7' },
  { type:'certificate',  label:'Certificate',        icon:'🏆', color:'#f59e0b' },
];

function DSModuleCard({ mod, phase, onDelete, onAddElement, onRemoveElement, onRename, elementConfigs, onConfigureElement }) {
  var R=React;
  var _e=R.useState(false); var editing=_e[0]; var setEditing=_e[1];
  var _d=R.useState(mod.title); var draft=_d[0]; var setDraft=_d[1];
  function commit(){ if(draft.trim()&&draft.trim()!==mod.title&&onRename) onRename(draft.trim()); setEditing(false); }
  function isConfigurable(type){ return DS_CONFIGURABLE_ELEMENTS.indexOf(type)!==-1; }
  function elMeta(type) {
    return DS_ELEMENT_TYPES.find(function(e){ return e.type === type; }) || { icon:'◈', color:'#8b90a7', label:type };
  }
  var slots = ['pre','post'];
  return (
    <div style={{ background:'#F5F7FB', border:'1px solid #EAECF4', borderRadius:9, overflow:'hidden', boxShadow:'0 1px 3px rgba(28,37,81,0.04)' }}>
      <div style={{ display:'flex', alignItems:'center', gap:8, padding:'8px 12px', borderBottom:'1px solid #EAECF4', background:'#fff' }}>
        <span style={{ fontSize:10, padding:'2px 8px', borderRadius:8, fontWeight:700,
          background:mod.type==='virtual'?'rgba(28,37,81,0.08)':'rgba(239,78,36,0.08)',
          color:mod.type==='virtual'?'#1C2551':'#EF4E24' }}>
          {mod.type==='virtual'?'🌐 Virtual':'🏛 In-Person'}
        </span>
        {editing ? (
          <input autoFocus value={draft} onChange={function(e){setDraft(e.target.value);}} onBlur={commit} onKeyDown={function(e){if(e.key==='Enter')commit();if(e.key==='Escape'){setDraft(mod.title);setEditing(false);}}} style={{flex:1,fontSize:12,fontWeight:700,color:'#1C2551',border:'none',borderBottom:'1.5px solid #EF4E24',outline:'none',background:'transparent',fontFamily:'Poppins,sans-serif',padding:'1px 0'}} />
        ) : (
          <span onClick={function(){setDraft(mod.title);setEditing(true);}} title="Click to rename" style={{flex:1,fontSize:12,fontWeight:700,color:'#1C2551',cursor:'text',borderBottom:'1px solid transparent'}} onMouseEnter={function(e){e.currentTarget.style.borderBottomColor='#D0D3E0';}} onMouseLeave={function(e){e.currentTarget.style.borderBottomColor='transparent';}}>{mod.title}</span>
        )}
        {mod.date && <span style={{ fontSize:10, color:'#8b90a7' }}>{(function(){ try{ return new Date(mod.date+'T00:00:00').toLocaleDateString('en-GB',{day:'numeric',month:'short'}); }catch(e){return mod.date;} })()}</span>}
        <button onClick={onDelete} style={{ width:18,height:18,border:'none',background:'none',cursor:'pointer',color:'#D0D3E0',fontSize:12,display:'flex',alignItems:'center',justifyContent:'center',padding:0 }}>✕</button>
      </div>
      <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr' }}>
        {slots.map(function(slot){
          return (
            <div key={slot} style={{ padding:'8px 10px', borderRight:slot==='pre'?'1px solid #EAECF4':undefined }}>
              <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:5 }}>
                <span style={{ fontSize:9, fontWeight:800, letterSpacing:0.8, color:slot==='pre'?'#6B73BF':'#EF4E24' }}>{slot==='pre'?'PRE-WORK':'POST-WORK'}</span>
                <button onClick={function(){ onAddElement(slot); }} style={{ width:16,height:16,borderRadius:4,background:slot==='pre'?'#6B73BF':'#EF4E24',border:'none',color:'#fff',cursor:'pointer',fontSize:11,display:'flex',alignItems:'center',justifyContent:'center',fontWeight:900,lineHeight:1 }}>+</button>
              </div>
              <div style={{ display:'flex', flexDirection:'column', gap:3 }}>
                {(mod[slot]||[]).map(function(el){
                  var m = elMeta(el.type);
                  return (
                    <div key={el.id}
                      onClick={isConfigurable(el.type)&&onConfigureElement?function(){onConfigureElement(el,slot);}:undefined}
                      style={{ display:'flex',alignItems:'center',gap:5,padding:'3px 7px',background:m.color+'12',border:'1px solid '+m.color+'28',borderRadius:5,cursor:isConfigurable(el.type)&&onConfigureElement?'pointer':'default' }}
                      onMouseEnter={isConfigurable(el.type)&&onConfigureElement?function(e){e.currentTarget.style.boxShadow='0 1px 4px rgba(28,37,81,0.1)';}:undefined}
                      onMouseLeave={isConfigurable(el.type)&&onConfigureElement?function(e){e.currentTarget.style.boxShadow='';}:undefined}>
                      <span style={{ fontSize:9,color:m.color,flexShrink:0 }}>{m.icon}</span>
                      <span style={{ flex:1,fontSize:10,color:'#1C2551',fontWeight:500,whiteSpace:'nowrap',overflow:'hidden',textOverflow:'ellipsis' }}>
                        {elementConfigs&&elementConfigs[el.id]?elementConfigs[el.id].label||elementConfigs[el.id].customTitle:el.label}
                      </span>
                      {isConfigurable(el.type)&&onConfigureElement&&!(elementConfigs&&elementConfigs[el.id])&&<span style={{fontSize:8,color:m.color,opacity:0.6,flexShrink:0}}>⚙</span>}
                      {elementConfigs&&elementConfigs[el.id]&&!elementConfigs[el.id].unlockDate&&<span style={{fontSize:8,color:'#22c55e',flexShrink:0}}>✓</span>}
                      {elementConfigs&&elementConfigs[el.id]&&elementConfigs[el.id].unlockDate&&(
                        <span title={'Unlocks '+elementConfigs[el.id].unlockDate+' '+elementConfigs[el.id].unlockTime} style={{fontSize:8,color:'#EF4E24',flexShrink:0,cursor:'default'}}>🔒</span>
                      )}
                      <button onClick={function(e){e.stopPropagation();onRemoveElement(slot,el.id);}} style={{ width:12,height:12,border:'none',background:'none',cursor:'pointer',color:'#D0D3E0',fontSize:9,display:'flex',alignItems:'center',justifyContent:'center',padding:0,flexShrink:0 }}>✕</button>
                    </div>
                  );
                })}
                {!(mod[slot]||[]).length && <span style={{ fontSize:10,color:'#D0D3E0',fontStyle:'italic' }}>None yet — click +</span>}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

function DSGanttPreview({ phases, progStart, progEnd }) {
  var GANTT_H = 300;
  function dbw(a,b){ return Math.max(1,Math.round((new Date(b+'T00:00:00')-new Date(a+'T00:00:00'))/86400000)); }
  var totalDays = dbw(progStart,progEnd);
  function getMonths(){
    var out=[]; var d=new Date(progStart+'T00:00:00'); d.setDate(1);
    var end=new Date(progEnd+'T00:00:00');
    while(d<=end){ out.push({date:d.toISOString().split('T')[0],label:d.toLocaleDateString('en-US',{month:'short',year:'2-digit'})}); d=new Date(d); d.setMonth(d.getMonth()+1); }
    return out;
  }
  if(!phases.length) return <div style={{height:80,display:'flex',alignItems:'center',justifyContent:'center',color:'#D0D3E0',fontSize:11}}>No phases yet</div>;
  var months=getMonths();
  return (
    <div style={{position:'relative',height:GANTT_H+'px',overflow:'hidden'}}>
      {months.map(function(m,i){
        var d=Math.max(0,dbw(progStart,m.date));
        var top=Math.min(GANTT_H-12,Math.round((d/totalDays)*GANTT_H));
        return (
          <React.Fragment key={i}>
            <div style={{position:'absolute',left:0,right:0,top:top+'px',borderTop:'1px dashed #F0F1F7',zIndex:0}}></div>
            <div style={{position:'absolute',left:0,top:top+'px',fontSize:8,color:'#8b90a7',fontWeight:700,lineHeight:'12px',width:28,textAlign:'right'}}>{m.label}</div>
          </React.Fragment>
        );
      })}
      {phases.map(function(p){
        var sd=Math.max(0,Math.round((new Date(p.startDate+'T00:00:00')-new Date(progStart+'T00:00:00'))/86400000));
        var ed=Math.min(totalDays,Math.round((new Date(p.endDate+'T00:00:00')-new Date(progStart+'T00:00:00'))/86400000));
        var top=Math.round((sd/totalDays)*GANTT_H);
        var h=Math.max(14,Math.round(((ed-sd)/totalDays)*GANTT_H)-2);
        return (
          <div key={p.id} style={{position:'absolute',left:32,right:0,top:top+'px',height:h+'px',background:p.color+'22',borderLeft:'3px solid '+p.color,borderRadius:'0 4px 4px 0',display:'flex',alignItems:'center',paddingLeft:5,overflow:'hidden',zIndex:1}}>
            <span style={{fontSize:8,fontWeight:700,color:p.color,whiteSpace:'nowrap',overflow:'hidden',textOverflow:'ellipsis'}}>{p.label}</span>
          </div>
        );
      })}
    </div>
  );
}

