                  var ptColor=pt?pt.color:'#1C2551';
                  return <button key={v} onClick={function(){setMode(v);}} style={{flex:1,padding:'8px',border:'1.5px solid '+(mode===v?ptColor:'#EAECF4'),borderRadius:8,background:mode===v?ptColor+'0C':'#fff',cursor:'pointer',fontSize:11,fontWeight:mode===v?700:400,color:mode===v?ptColor:'#8b90a7',fontFamily:'Poppins,sans-serif'}}>{l}</button>;
