function BreakoutWorkflow({ prog }) {
  const [step, setStep] = React.useState('setup');
  const [groupCount, setGroupCount] = React.useState(4);
  const [duration, setDuration] = React.useState(15);
  const [groups, setGroups] = React.useState([]);
  const [remaining, setRemaining] = React.useState(0);
  const [running, setRunning] = React.useState(true);
  const [msg, setMsg] = React.useState('');
  const NAMES = ['Riya Sharma','Arjun Mehta','Deepak Rao','Priti Shah','Meera Nair','Vivek Kumar','Sneha Pillai','Rahul Das','Kavya Menon','Anita Joshi','Saurabh Verma','Divya Rajan','Nikhil Jain','Pooja Iyer','Karan Malhotra','Rohit Gupta'];

  function startBreakout() {
    const shuffled = [...NAMES].sort(() => Math.random() - 0.5).slice(0, prog ? prog.participants : 12);
    const g = Array.from({ length: groupCount }, (_, i) => ({ name:'Group '+(i+1), members:[] }));
    shuffled.forEach((n, i) => g[i % groupCount].members.push(n));
    setGroups(g); setRemaining(duration * 60); setRunning(true); setStep('active');
  }

  React.useEffect(() => {
    if (step !== 'active' || !running || remaining <= 0) return;
    const iv = setInterval(() => setRemaining(r => r <= 1 ? 0 : r - 1), 1000);
    return () => clearInterval(iv);
  }, [step, running, remaining]);

  const mins = String(Math.floor(remaining / 60)).padStart(2, '0');
  const secs = String(remaining % 60).padStart(2, '0');

  if (step === 'setup') return (
    <div style={{ display:'flex', flexDirection:'column', gap:16 }}>
      <div>
        <label style={{ fontSize:11, fontWeight:700, color:'#8b90a7', letterSpacing:0.5, display:'block', marginBottom:10 }}>NUMBER OF GROUPS</label>
        <div style={{ display:'flex', gap:8, flexWrap:'wrap' }}>
          {[2,3,4,5,6,8].map(n=>(
            <button key={n} onClick={()=>setGroupCount(n)} style={{ width:44, height:44, border:'1.5px solid '+(groupCount===n?'#EF4E24':'#EAECF4'), borderRadius:10, background:groupCount===n?'rgba(239,78,36,0.08)':'#fff', color:groupCount===n?'#EF4E24':'#8b90a7', fontSize:16, fontWeight:groupCount===n?800:400, cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>{n}</button>
          ))}
        </div>
        <div style={{ fontSize:11, color:'#8b90a7', marginTop:6 }}>~{Math.ceil((prog?prog.participants:12)/groupCount)} participants per group</div>
      </div>
      <div>
        <label style={{ fontSize:11, fontWeight:700, color:'#8b90a7', letterSpacing:0.5, display:'block', marginBottom:10 }}>DURATION</label>
        <div style={{ display:'flex', gap:8 }}>
          {[5,10,15,20,30].map(m=>(
            <button key={m} onClick={()=>setDuration(m)} style={{ padding:'8px 14px', border:'1.5px solid '+(duration===m?'#EF4E24':'#EAECF4'), borderRadius:8, background:duration===m?'rgba(239,78,36,0.08)':'#fff', color:duration===m?'#EF4E24':'#8b90a7', fontSize:12, fontWeight:duration===m?700:400, cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>{m} min</button>
          ))}
        </div>
      </div>
      <button onClick={startBreakout} style={{ padding:'13px', background:'#EF4E24', border:'none', borderRadius:10, color:'#fff', fontWeight:700, fontSize:14, cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>Start Breakout →</button>
    </div>
  );

  return (
    <div style={{ display:'flex', flexDirection:'column', gap:16 }}>
      <div style={{ display:'flex', alignItems:'center', gap:16, padding:'14px 18px', background:'#1C2551', borderRadius:12 }}>
        <div style={{ textAlign:'center' }}>
          <div style={{ fontSize:32, fontWeight:800, color:'#fff', fontFamily:'monospace' }}>{mins}:{secs}</div>
          <div style={{ fontSize:10, color:'rgba(255,255,255,0.5)', marginTop:2 }}>REMAINING</div>
        </div>
        <div style={{ flex:1, height:6, background:'rgba(255,255,255,0.15)', borderRadius:99 }}>
          <div style={{ height:'100%', width:(remaining/(duration*60)*100)+'%', background:'#EF4E24', borderRadius:99, transition:'width 1s' }}></div>
        </div>
        <button onClick={()=>setRunning(r=>!r)} style={{ padding:'8px 16px', border:'1px solid rgba(255,255,255,0.2)', borderRadius:8, background:'transparent', color:'#fff', fontSize:12, fontWeight:700, cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>{running?'Pause':'Resume'}</button>
        <button onClick={()=>setStep('setup')} style={{ padding:'8px 16px', border:'none', borderRadius:8, background:'#EF4E24', color:'#fff', fontSize:12, fontWeight:700, cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>Recall All</button>
      </div>
      <div style={{ display:'grid', gridTemplateColumns:'repeat(2,1fr)', gap:10 }}>
        {groups.map((g, i) => (
          <div key={i} style={{ background:'#F5F7FB', borderRadius:10, padding:'12px 14px', border:'1px solid #EAECF4' }}>
            <div style={{ fontSize:12, fontWeight:700, color:'#EF4E24', marginBottom:8 }}>{g.name}</div>
            {g.members.map((m, mi) => (
              <div key={mi} style={{ display:'flex', alignItems:'center', gap:7, marginBottom:5 }}>
                <div style={{ width:20, height:20, borderRadius:'50%', background:'#1C2551', color:'#fff', fontSize:8, fontWeight:700, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>{m[0]}</div>
                <span style={{ fontSize:11, color:'#1C2551' }}>{m}</span>
              </div>
            ))}
          </div>
        ))}
      </div>
      <div style={{ display:'flex', gap:8 }}>
        <input value={msg} onChange={e=>setMsg(e.target.value)} placeholder="Broadcast a message to all groups…" style={{ flex:1, border:'1.5px solid #EAECF4', borderRadius:8, padding:'9px 12px', fontSize:12, fontFamily:'Poppins,sans-serif', color:'#1C2551', outline:'none' }} />
        <button onClick={()=>setMsg('')} style={{ padding:'9px 16px', background:'#1C2551', border:'none', borderRadius:8, color:'#fff', fontSize:12, fontWeight:700, cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>Send</button>
      </div>
    </div>
  );
}

function TimerWorkflow() {
  const [step, setStep] = React.useState('setup');
  const [preset, setPreset] = React.useState(10);
  const [custom, setCustom] = React.useState('');
  const [remaining, setRemaining] = React.useState(0);
  const [total, setTotal] = React.useState(0);
  const [running, setRunning] = React.useState(false);
  const [visible, setVisible] = React.useState(true);

  React.useEffect(() => {
    if (!running || remaining <= 0) return;
    const iv = setInterval(() => setRemaining(r => { if (r <= 1) { setRunning(false); return 0; } return r - 1; }), 1000);
    return () => clearInterval(iv);
  }, [running, remaining]);

  function start() {
    const mins = custom ? parseInt(custom) : preset;
    const secs = mins * 60;
    setTotal(secs); setRemaining(secs); setRunning(true); setStep('active');
  }

  const pct = total > 0 ? (remaining / total) * 100 : 0;
  const mins = String(Math.floor(remaining / 60)).padStart(2, '0');
  const secs = String(remaining % 60).padStart(2, '0');
  const r = 70, circ = 2 * Math.PI * r;

  if (step === 'setup') return (
    <div style={{ display:'flex', flexDirection:'column', gap:20 }}>
      <div>
        <label style={{ fontSize:11, fontWeight:700, color:'#8b90a7', letterSpacing:0.5, display:'block', marginBottom:10 }}>PRESET DURATION</label>
        <div style={{ display:'flex', gap:8, flexWrap:'wrap' }}>
          {[1,5,10,15,20,30,45,60].map(m=>(
            <button key={m} onClick={()=>{setPreset(m);setCustom('');}} style={{ padding:'8px 14px', border:'1.5px solid '+(preset===m&&!custom?'#EF4E24':'#EAECF4'), borderRadius:8, background:preset===m&&!custom?'rgba(239,78,36,0.08)':'#fff', color:preset===m&&!custom?'#EF4E24':'#8b90a7', fontSize:12, fontWeight:preset===m&&!custom?700:400, cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>{m} min</button>
          ))}
        </div>
      </div>
      <div>
        <label style={{ fontSize:11, fontWeight:700, color:'#8b90a7', letterSpacing:0.5, display:'block', marginBottom:8 }}>CUSTOM (MINUTES)</label>
        <input type="number" value={custom} onChange={e=>setCustom(e.target.value)} placeholder="e.g. 25"
          style={{ width:100, border:'1.5px solid #EAECF4', borderRadius:8, padding:'8px 12px', fontSize:14, fontFamily:'Poppins,sans-serif', color:'#1C2551', outline:'none' }} />
      </div>
      <div style={{ display:'flex', alignItems:'center', gap:10 }}>
        <div onClick={()=>setVisible(v=>!v)} style={{ width:40, height:22, borderRadius:11, background:visible?'#EF4E24':'#D0D3E0', cursor:'pointer', position:'relative', transition:'background 0.2s' }}>
          <div style={{ position:'absolute', top:3, left:visible?20:3, width:16, height:16, borderRadius:'50%', background:'#fff', transition:'left 0.2s' }}></div>
        </div>
        <span style={{ fontSize:12, color:'#1C2551' }}>Visible to all participants</span>
      </div>
      <button onClick={start} style={{ padding:'13px', background:'#EF4E24', border:'none', borderRadius:10, color:'#fff', fontWeight:700, fontSize:14, cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>Start Timer →</button>
    </div>
  );

  return (
    <div style={{ display:'flex', flexDirection:'column', alignItems:'center', gap:24 }}>
      <svg width="180" height="180" viewBox="0 0 180 180">
        <circle cx="90" cy="90" r={r} fill="none" stroke="#F0F1F7" strokeWidth="10" />
        <circle cx="90" cy="90" r={r} fill="none" stroke={remaining===0?'#22c55e':'#EF4E24'} strokeWidth="10"
          strokeDasharray={circ} strokeDashoffset={circ*(1-pct/100)} strokeLinecap="round"
          transform="rotate(-90 90 90)" style={{ transition:'stroke-dashoffset 1s' }} />
        <text x="90" y="85" textAnchor="middle" style={{ fontSize:32, fontWeight:800, fontFamily:'monospace', fill:'#1C2551' }}>{mins}:{secs}</text>
        <text x="90" y="108" textAnchor="middle" style={{ fontSize:12, fill:'#8b90a7', fontFamily:'Poppins,sans-serif' }}>{remaining===0?"Time's up!":running?'Running...':'Paused'}</text>
      </svg>
      {visible && <div style={{ padding:'8px 16px', background:'rgba(239,78,36,0.08)', border:'1px solid rgba(239,78,36,0.2)', borderRadius:20, fontSize:11, color:'#EF4E24', fontWeight:600 }}>Visible to all participants</div>}
      <div style={{ display:'flex', gap:10 }}>
        {remaining > 0 && (
          <button onClick={()=>setRunning(r=>!r)} style={{ padding:'12px 28px', border:'1.5px solid #EAECF4', borderRadius:10, background:'#fff', color:'#1C2551', fontWeight:700, fontSize:14, cursor:'pointer', fontFamily:'Poppins,sans-serif', minWidth:120 }}>{running?'Pause':'Resume'}</button>
        )}
        <button onClick={()=>{setStep('setup');setRunning(false);setRemaining(0);}} style={{ padding:'12px 28px', border:'none', borderRadius:10, background:'#EF4E24', color:'#fff', fontWeight:700, fontSize:14, cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>{remaining===0?'New Timer':'Stop'}</button>
      </div>
    </div>
  );
}

function AttendanceWorkflow({ prog }) {
  const [code] = React.useState(() => 'XA' + Math.random().toString(36).substr(2,4).toUpperCase());
  const link = 'xa-lms.fourward.in/join/' + code;
  const ALL_NAMES = ['Riya Sharma','Arjun Mehta','Deepak Rao','Priti Shah','Meera Nair','Vivek Kumar','Sneha Pillai','Rahul Das','Kavya Menon','Anita Joshi','Saurabh Verma','Divya Rajan','Nikhil Jain','Pooja Iyer','Karan Malhotra','Rohit Gupta','Priya Nair','Vivek Sharma'];
  const total = prog ? Math.min(prog.participants, ALL_NAMES.length) : 10;
  const names = ALL_NAMES.slice(0, total);
  const [checkedIn, setCheckedIn] = React.useState([names[0]]);
  const [copied, setCopied] = React.useState(false);

  React.useEffect(() => {
    if (checkedIn.length >= names.length) return;
    const timeout = setTimeout(() => {
      setCheckedIn(prev => {
        const remaining = names.filter(n => !prev.includes(n));
        if (remaining.length === 0) return prev;
        return [...prev, remaining[Math.floor(Math.random() * remaining.length)]];
      });
    }, 2000 + Math.random() * 2000);
    return () => clearTimeout(timeout);
  }, [checkedIn, names]);

  return (
    <div style={{ display:'flex', gap:24, flexWrap:'wrap' }}>
      <div style={{ display:'flex', flexDirection:'column', alignItems:'center', gap:12, flexShrink:0 }}>
        <div style={{ padding:16, background:'#F5F7FB', borderRadius:12, border:'2px solid #EAECF4' }}>
          <QRCodeSVG code={code} />
        </div>
        <div style={{ fontSize:13, fontWeight:700, color:'#1C2551' }}>Session Code: <span style={{ color:'#EF4E24', letterSpacing:2 }}>{code}</span></div>
        <div style={{ display:'flex', gap:8, alignItems:'center', background:'#F5F7FB', borderRadius:8, padding:'8px 12px', maxWidth:220 }}>
          <span style={{ fontSize:10, color:'#8b90a7', flex:1, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{link}</span>
          <button onClick={()=>{setCopied(true);setTimeout(()=>setCopied(false),2000);}} style={{ padding:'4px 10px', background:copied?'#22c55e':'#EF4E24', border:'none', borderRadius:6, color:'#fff', fontSize:10, fontWeight:700, cursor:'pointer', fontFamily:'Poppins,sans-serif', flexShrink:0 }}>{copied?'✓':'Copy'}</button>
        </div>
      </div>
      <div style={{ flex:1, minWidth:200 }}>
        <div style={{ display:'flex', justifyContent:'space-between', marginBottom:12 }}>
          <span style={{ fontSize:13, fontWeight:700, color:'#1C2551' }}>Attendance</span>
          <span style={{ fontSize:13, fontWeight:800, color:'#EF4E24' }}>{checkedIn.length}<span style={{ fontSize:11, color:'#8b90a7', fontWeight:400 }}>/{total}</span> <span style={{ fontSize:12, color:'#22c55e', fontWeight:700 }}>({Math.round(checkedIn.length/total*100)}%)</span></span>
        </div>
        <div style={{ height:6, background:'#F0F1F7', borderRadius:99, marginBottom:14 }}>
          <div style={{ height:'100%', width:(checkedIn.length/total*100)+'%', background:'#22c55e', borderRadius:99, transition:'width 0.5s' }}></div>
        </div>
        <div style={{ maxHeight:240, overflowY:'auto', display:'flex', flexDirection:'column', gap:6 }}>
          {names.map((name, i) => {
            const present = checkedIn.includes(name);
            return (
              <div key={i} style={{ display:'flex', alignItems:'center', gap:10, padding:'7px 10px', background:present?'rgba(34,197,94,0.06)':'#F5F7FB', borderRadius:8, border:'1px solid '+(present?'rgba(34,197,94,0.2)':'#EAECF4') }}>
                <div style={{ width:7, height:7, borderRadius:'50%', background:present?'#22c55e':'#D0D3E0', flexShrink:0 }}></div>
                <span style={{ fontSize:12, color:'#1C2551', flex:1 }}>{name}</span>
                <span style={{ fontSize:10, fontWeight:700, color:present?'#22c55e':'#8b90a7' }}>{present?'✓ Present':'Waiting'}</span>
              </div>
            );
          })}
        </div>
        <button style={{ width:'100%', marginTop:12, padding:'11px', background:'#EF4E24', border:'none', borderRadius:10, color:'#fff', fontWeight:700, fontSize:13, cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>Save Attendance Record</button>
      </div>
    </div>
  );
}

function SessionToolModal({ tool, onClose, prog }) {
  const TOOLS = {
    'Live Poll': { icon:'▶', color:'#EF4E24', desc:'Launch a real-time poll to your cohort' },
    'Breakout Groups': { icon:'⬡', color:'#6B73BF', desc:'Split participants into randomized groups' },
    'Timer': { icon:'⏱', color:'#1C2551', desc:'Set a visible countdown for your participants' },
    'Attendance': { icon:'◎', color:'#22c55e', desc:'QR-based real-time check-in' },
  };
  const meta = TOOLS[tool] || {};
  return ReactDOM.createPortal(
    <div onClick={e=>{if(e.target===e.currentTarget)onClose();}} style={{position:'fixed',inset:0,background:'rgba(28,37,81,0.55)',zIndex:2000,display:'flex',alignItems:'center',justifyContent:'center',padding:'32px 20px',fontFamily:'Poppins,sans-serif'}}>
      <div style={{background:'#fff',borderRadius:20,width:'100%',maxWidth:640,maxHeight:'90vh',display:'flex',flexDirection:'column',overflow:'hidden',boxShadow:'0 24px 80px rgba(28,37,81,0.28)'}}>
        <div style={{padding:'20px 24px',borderBottom:'1px solid #EAECF4',display:'flex',alignItems:'center',gap:12,flexShrink:0}}>
          <div style={{width:40,height:40,borderRadius:10,background:meta.color+'15',display:'flex',alignItems:'center',justifyContent:'center',fontSize:18,color:meta.color,flexShrink:0}}>{meta.icon}</div>
          <div style={{flex:1}}>
            <div style={{fontSize:15,fontWeight:700,color:'#1C2551'}}>{tool}</div>
            <div style={{fontSize:11,color:'#8b90a7'}}>{meta.desc}</div>
          </div>
          <button onClick={onClose} style={{width:28,height:28,border:'1px solid #EAECF4',borderRadius:'50%',background:'#fff',cursor:'pointer',fontSize:14,color:'#8b90a7',display:'flex',alignItems:'center',justifyContent:'center',fontFamily:'Poppins,sans-serif',flexShrink:0}}>✕</button>
        </div>
        <div style={{flex:1,overflowY:'auto',padding:'24px'}}>
          {tool==='Live Poll'       && <LivePollWorkflow />}
          {tool==='Breakout Groups' && <BreakoutWorkflow prog={prog} />}
          {tool==='Timer'           && <TimerWorkflow />}
          {tool==='Attendance'      && <AttendanceWorkflow prog={prog} />}
        </div>
      </div>
    </div>,
    document.body
  );
}

