function CoachingTimelinePanel({ participant, onClose }) {
  const data = COACHING_DATA[participant];
  if (!data) return null;
  const [activeTab, setActiveTab] = React.useState('timeline');
  const [noteText, setNoteText] = React.useState('');
  const pendingActions = data.actions.filter(a => !a.done);
  const doneActions = data.actions.filter(a => a.done);

  return ReactDOM.createPortal(
    <div onClick={e=>{if(e.target===e.currentTarget)onClose();}} style={{position:'fixed',inset:0,background:'rgba(28,37,81,0.5)',zIndex:2000,display:'flex',justifyContent:'flex-end',fontFamily:'Poppins,sans-serif'}}>
      <div style={{width:'min(560px,100vw)',height:'100%',background:'#fff',boxShadow:'-8px 0 40px rgba(28,37,81,0.16)',display:'flex',flexDirection:'column',overflow:'hidden'}}>
        {/* Header */}
        <div style={{background:'linear-gradient(135deg,#1C2551,#2d3a7c)',padding:'20px 24px',flexShrink:0}}>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:14}}>
            <div style={{display:'flex',alignItems:'center',gap:12}}>
              <div style={{width:46,height:46,borderRadius:'50%',background:data.color,color:'#fff',fontWeight:800,fontSize:15,display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0}}>{data.avatar}</div>
              <div>
                <div style={{color:'#fff',fontWeight:700,fontSize:16}}>{participant}</div>
                <div style={{color:'rgba(255,255,255,0.5)',fontSize:11,marginTop:2}}>{data.role}</div>
              </div>
            </div>
            <button onClick={onClose} style={{width:28,height:28,border:'1px solid rgba(255,255,255,0.2)',borderRadius:'50%',background:'transparent',cursor:'pointer',color:'rgba(255,255,255,0.7)',fontSize:13,display:'flex',alignItems:'center',justifyContent:'center',fontFamily:'Poppins,sans-serif'}}>✕</button>
          </div>
          <div style={{display:'flex',gap:16,marginBottom:16}}>
            <div><div style={{fontSize:20,fontWeight:800,color:'#EF4E24'}}>{data.totalSessions}<span style={{fontSize:12,color:'rgba(255,255,255,0.4)',fontWeight:400}}>/{data.maxSessions}</span></div><div style={{fontSize:10,color:'rgba(255,255,255,0.4)',marginTop:2}}>Sessions Done</div></div>
            <div><div style={{fontSize:20,fontWeight:800,color:'#fff'}}>{pendingActions.length}</div><div style={{fontSize:10,color:'rgba(255,255,255,0.4)',marginTop:2}}>Actions Pending</div></div>
            <div><div style={{fontSize:20,fontWeight:800,color:'#fff'}}>{data.goals.length}</div><div style={{fontSize:10,color:'rgba(255,255,255,0.4)',marginTop:2}}>Goals Active</div></div>
          </div>
          <div style={{height:4,background:'rgba(255,255,255,0.1)',borderRadius:99}}>
            <div style={{height:'100%',width:(data.totalSessions/data.maxSessions*100)+'%',background:'#EF4E24',borderRadius:99}}></div>
          </div>
          <div style={{fontSize:10,color:'rgba(255,255,255,0.4)',marginTop:4}}>Next: {data.nextSession}</div>
        </div>
        {/* Tabs */}
        <div style={{display:'flex',borderBottom:'1px solid #EAECF4',flexShrink:0}}>
          {[['timeline','Timeline'],['goals','Goals'],['actions','Actions'],['notes','Notes']].map(([key,label])=>(
            <button key={key} onClick={()=>setActiveTab(key)} style={{flex:1,padding:'11px 0',border:'none',background:'transparent',cursor:'pointer',fontSize:12,fontWeight:activeTab===key?700:400,color:activeTab===key?'#EF4E24':'#8b90a7',borderBottom:activeTab===key?'2.5px solid #EF4E24':'2.5px solid transparent',fontFamily:'Poppins,sans-serif'}}>
              {label}{key==='actions'&&pendingActions.length>0?<span style={{marginLeft:5,background:'#EF4E24',color:'#fff',borderRadius:'50%',width:16,height:16,fontSize:9,fontWeight:700,display:'inline-flex',alignItems:'center',justifyContent:'center'}}>{pendingActions.length}</span>:null}
            </button>
          ))}
        </div>
        {/* Content */}
        <div style={{flex:1,overflowY:'auto',padding:'20px 24px'}}>
          {/* Timeline tab */}
          {activeTab==='timeline' && (
            <div style={{position:'relative'}}>
              <div style={{position:'absolute',left:18,top:0,bottom:0,width:2,background:'#EAECF4'}}></div>
              {data.sessions.map((s,i)=>(
                <div key={i} style={{display:'flex',gap:16,marginBottom:20,position:'relative'}}>
                  <div style={{width:38,height:38,borderRadius:'50%',border:'2px solid',flexShrink:0,zIndex:1,display:'flex',alignItems:'center',justifyContent:'center',fontSize:13,fontWeight:700,
                    borderColor:s.status==='done'?'#1C2551':s.status==='upcoming'?'#EF4E24':'#D0D3E0',
                    background:s.status==='done'?'#1C2551':s.status==='upcoming'?'#EF4E24':'#F5F7FB',
                    color:s.status==='locked'?'#aaa':'#fff'}}>
                    {s.status==='done'?'✓':s.status==='upcoming'?'●':(i+1)}
                  </div>
                  <div style={{flex:1,paddingTop:4}}>
                    <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:4}}>
                      <div style={{fontSize:13,fontWeight:600,color:s.status==='locked'?'#aaa':'#1C2551',lineHeight:1.3}}>{s.topic}</div>
                      <span style={{fontSize:10,color:'#8b90a7',flexShrink:0,marginLeft:8}}>{s.date}</span>
                    </div>
                    {s.status==='upcoming' && <span style={{display:'inline-block',fontSize:10,fontWeight:700,color:'#EF4E24',background:'rgba(239,78,36,0.08)',borderRadius:10,padding:'2px 8px',marginBottom:4}}>Upcoming</span>}
                    {s.outcome && <div style={{fontSize:12,color:'#4a5074',lineHeight:1.6,background:'#F5F7FB',borderRadius:8,padding:'8px 10px',marginTop:6}}>{s.outcome}</div>}
                    {s.status==='upcoming' && (
                      <div style={{marginTop:8,display:'flex',gap:8}}>
                        <button style={{padding:'5px 12px',border:'none',borderRadius:6,background:'#EF4E24',color:'#fff',fontSize:11,fontWeight:700,cursor:'pointer',fontFamily:'Poppins,sans-serif'}}>Prepare Notes</button>
                        <button style={{padding:'5px 12px',border:'1px solid #EAECF4',borderRadius:6,background:'#fff',color:'#8b90a7',fontSize:11,fontWeight:600,cursor:'pointer',fontFamily:'Poppins,sans-serif'}}>Reschedule</button>
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
          {/* Goals tab */}
          {activeTab==='goals' && (
            <div style={{display:'flex',flexDirection:'column',gap:16}}>
              {data.goals.map((g,i)=>(
                <div key={i} style={{background:'#F5F7FB',borderRadius:12,padding:'16px'}}>
                  <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:10}}>
                    <div style={{fontSize:14,fontWeight:700,color:'#1C2551'}}>{g.label}</div>
                    <div style={{textAlign:'right'}}>
                      <div style={{fontSize:22,fontWeight:800,color:g.color}}>{g.pct}%</div>
                      <div style={{fontSize:10,color:'#8b90a7'}}>Target: {g.target}</div>
                    </div>
                  </div>
                  <div style={{height:8,background:'#E0E3EF',borderRadius:99,marginBottom:8}}>
                    <div style={{height:'100%',width:g.pct+'%',background:g.color,borderRadius:99,transition:'width 0.4s'}}></div>
                  </div>
                  <div style={{display:'flex',justifyContent:'space-between',fontSize:10,color:'#8b90a7'}}>
                    <span>Baseline: 35%</span><span>Current: {g.pct}%</span><span>Target: 90%</span>
                  </div>
                </div>
              ))}
              <div style={{background:'rgba(239,78,36,0.04)',border:'1px solid rgba(239,78,36,0.15)',borderRadius:12,padding:'14px 16px'}}>
                <div style={{fontSize:11,fontWeight:700,color:'#EF4E24',marginBottom:6}}>✦ AI Coach Insight</div>
                <div style={{fontSize:12,color:'#1C2551',lineHeight:1.6}}>{data.aiNote}</div>
              </div>
            </div>
          )}
          {/* Actions tab */}
          {activeTab==='actions' && (
            <div style={{display:'flex',flexDirection:'column',gap:12}}>
              {pendingActions.length > 0 && (
                <>
                  <div style={{fontSize:11,fontWeight:700,color:'#8b90a7',letterSpacing:0.5}}>PENDING ({pendingActions.length})</div>
                  {pendingActions.map((a,i)=>(
                    <div key={i} style={{display:'flex',gap:12,padding:'12px 14px',background:a.urgent?'rgba(239,78,36,0.04)':'#F5F7FB',border:'1px solid '+(a.urgent?'rgba(239,78,36,0.2)':'#EAECF4'),borderRadius:10,alignItems:'center'}}>
                      <div style={{width:18,height:18,borderRadius:'50%',border:'2px solid '+(a.urgent?'#EF4E24':'#D0D3E0'),flexShrink:0}}></div>
                      <div style={{flex:1}}>
                        <div style={{fontSize:13,color:'#1C2551',fontWeight:a.urgent?600:400}}>{a.text}</div>
                        <div style={{fontSize:10,color:a.urgent?'#EF4E24':'#8b90a7',marginTop:2}}>Due: {a.due}{a.urgent?' · Overdue':''}</div>
                      </div>
                      <button style={{padding:'5px 10px',border:'1px solid #EAECF4',borderRadius:6,background:'#fff',color:'#8b90a7',fontSize:10,fontWeight:600,cursor:'pointer',fontFamily:'Poppins,sans-serif',whiteSpace:'nowrap'}}>Nudge</button>
                    </div>
                  ))}
                </>
              )}
              {doneActions.length > 0 && (
                <>
                  <div style={{fontSize:11,fontWeight:700,color:'#8b90a7',letterSpacing:0.5,marginTop:8}}>COMPLETED ({doneActions.length})</div>
                  {doneActions.map((a,i)=>(
                    <div key={i} style={{display:'flex',gap:12,padding:'12px 14px',background:'rgba(34,197,94,0.04)',border:'1px solid rgba(34,197,94,0.15)',borderRadius:10,alignItems:'center',opacity:0.8}}>
                      <div style={{width:18,height:18,borderRadius:'50%',background:'#22c55e',border:'2px solid #22c55e',display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0,fontSize:10,color:'#fff',fontWeight:700}}>✓</div>
                      <div style={{flex:1}}><div style={{fontSize:13,color:'#4a5074',textDecoration:'line-through'}}>{a.text}</div><div style={{fontSize:10,color:'#8b90a7',marginTop:2}}>Completed · Due was {a.due}</div></div>
                    </div>
                  ))}
                </>
              )}
            </div>
          )}
          {/* Notes tab */}
          {activeTab==='notes' && (
            <div style={{display:'flex',flexDirection:'column',gap:14}}>
              <div style={{fontSize:12,color:'#8b90a7',fontStyle:'italic'}}>Session 3 · May 1, 2026</div>
              <textarea value={noteText || 'Session 3: Discussed progress on stakeholder mapping exercise. Riya showed strong self-awareness around her communication style gaps. Set 2 new actions: (1) structured 1:1 with CFO, (2) attend leadership workshop...'} onChange={e=>setNoteText(e.target.value)}
                style={{width:'100%',border:'1.5px solid #EAECF4',borderRadius:10,padding:'12px 14px',fontSize:13,fontFamily:'Poppins,sans-serif',color:'#1C2551',outline:'none',resize:'vertical',minHeight:140,boxSizing:'border-box',lineHeight:1.6}} />
              <div style={{display:'flex',gap:8}}>
                <button style={{flex:1,padding:'10px',border:'1px solid #EAECF4',borderRadius:8,background:'#fff',color:'#8b90a7',fontSize:12,fontWeight:600,cursor:'pointer',fontFamily:'Poppins,sans-serif'}}>Mark Private</button>
                <button style={{flex:2,padding:'10px',border:'none',borderRadius:8,background:'#EF4E24',color:'#fff',fontSize:12,fontWeight:700,cursor:'pointer',fontFamily:'Poppins,sans-serif'}}>Save Notes</button>
              </div>
              <div style={{background:'#F5F7FB',borderRadius:10,padding:'14px'}}>
                <div style={{fontSize:11,fontWeight:700,color:'#8b90a7',letterSpacing:0.5,marginBottom:8}}>PREVIOUS SESSIONS</div>
                {['May 1 · Executive Communication Review','Apr 17 · Stakeholder Mapping Exercise','Apr 3 · Goal Setting & Orientation'].map((s,i)=>(
                  <div key={i} style={{padding:'8px 0',borderBottom:i<2?'1px solid #EAECF4':'none',fontSize:12,color:'#6B73BF',cursor:'pointer'}}>{s}</div>
                ))}
              </div>
            </div>
          )}
        </div>
        {/* Footer CTA */}
        <div style={{padding:'14px 24px',borderTop:'1px solid #EAECF4',background:'#FAFBFC',flexShrink:0}}>
          <button style={{width:'100%',padding:'12px',background:'#1C2551',border:'none',borderRadius:10,color:'#fff',fontWeight:700,fontSize:13,cursor:'pointer',fontFamily:'Poppins,sans-serif'}}>
            Schedule Next Session → {data.nextSession}
          </button>
        </div>
      </div>
    </div>,
    document.body
  );
}

function FacultyCoaching() {
  const [selectedParticipant, setSelectedParticipant] = React.useState(null);
  const participants = [{name:'Riya Sharma',sessions:3,goals:2,actions:1},{name:'Vivek Kumar',sessions:2,goals:3,actions:2},{name:'Meera Iyer',sessions:3,goals:2,actions:3}];
  const totalPending = participants.reduce((a,p)=>a+p.actions,0);
  const avgProgress = Math.round(Object.values(COACHING_DATA).flatMap(d=>d.goals).reduce((a,g)=>a+g.pct,0)/Object.values(COACHING_DATA).flatMap(d=>d.goals).length);
  return (
    <div style={fStyles.page}>
      {/* Summary Dashboard */}
      <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:12 }}>
        {[
          ['3','Participants','Active this cohort','◎','#1C2551'],
          ['8','Sessions Done','of 18 planned','⬡','#EF4E24'],
          [totalPending,'Actions Pending','Across all participants','✦','#f59e0b'],
          [avgProgress+'%','Avg Goal Progress','Across all goals','◆','#22c55e'],
        ].map(([val,label,sub,icon,color],i)=>(
          <FCard key={i} style={{ padding:'14px 16px' }}>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start' }}>
              <div>
                <div style={{ fontSize:11, color:'#8b90a7', marginBottom:4 }}>{label}</div>
                <div style={{ fontSize:26, fontWeight:800, color }}>{val}</div>
                <div style={{ fontSize:10, color:'#8b90a7', marginTop:3 }}>{sub}</div>
              </div>
              <span style={{ fontSize:20, opacity:0.35, color }}>{icon}</span>
            </div>
          </FCard>
        ))}
      </div>
      <FCard style={{ background:'linear-gradient(135deg,#1C2551,#2d3a7c)', border:'none', padding:'14px 20px', display:'flex', alignItems:'center', gap:14 }}>
        <span style={{ fontSize:16 }}>✦</span>
        <div style={{ flex:1 }}>
          <div style={{ fontSize:11, fontWeight:700, color:'rgba(255,255,255,0.5)', letterSpacing:0.5, marginBottom:2 }}>AI COACHING PULSE</div>
          <div style={{ fontSize:13, color:'#fff', fontWeight:600 }}>Meera Iyer has the highest momentum this week. Vivek Kumar has 2 overdue actions — consider a check-in nudge before his next session.</div>
        </div>
      </FCard>
      <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:16 }}>
        <FCard>
          <div style={{ fontWeight:700, fontSize:14, color:'#1C2551', marginBottom:14 }}>Individual Coaching Tracker</div>
          {[{name:'Riya Sharma',sessions:3,goals:2,actions:1},{name:'Vivek Kumar',sessions:2,goals:3,actions:2},{name:'Meera Iyer',sessions:3,goals:2,actions:3}].map((p,i) => (
            <div key={i} onClick={()=>setSelectedParticipant(p.name)} style={{ padding:'12px 0', borderBottom:'1px solid #EAECF4', cursor:'pointer' }}>
              <div style={{ display:'flex', justifyContent:'space-between', marginBottom:8 }}>
                <span style={{ fontWeight:600, fontSize:13, color:'#1C2551' }}>{p.name}</span>
                <span style={{ fontSize:11, color:'#8b90a7' }}>{p.sessions} sessions completed</span>
              </div>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                <div style={{ display:'flex', gap:8 }}>
                  <FBadge label={`${p.goals} Goals Set`} color="#1C2551" />
                  <FBadge label={`${p.actions} Actions Pending`} color={p.actions>1?'#EF4E24':'#22c55e'} />
                </div>
                <span style={{ fontSize:11, color:'#EF4E24', fontWeight:600 }}>View →</span>
              </div>
            </div>
          ))}
        </FCard>
        <FCard style={{ background:'rgba(239,78,36,0.03)', border:'1px solid rgba(239,78,36,0.15)' }}>
          <div style={{ fontSize:11, fontWeight:700, color:'#EF4E24', marginBottom:10 }}>✦ Coaching Insight Engine</div>
          <div style={{ fontWeight:700, fontSize:13, color:'#1C2551', marginBottom:8 }}>Post-Session Insights — May 3 Group Coaching</div>
          {[['Team Energy','High — participants were engaged and challenged'],['Key Theme','Stakeholder buy-in for new initiatives'],['Recommended Focus','Next session: navigating organizational politics']].map(([k,v],i) => (
            <div key={i} style={{ padding:'8px 0', borderBottom:'1px solid rgba(239,78,36,0.1)' }}>
              <div style={{ fontSize:10, color:'#EF4E24', fontWeight:700 }}>{k}</div>
              <div style={{ fontSize:12, color:'#1C2551', marginTop:2 }}>{v}</div>
            </div>
          ))}
        </FCard>
        <FCard>
          <div style={{ fontWeight:700, fontSize:14, color:'#1C2551', marginBottom:14 }}>Session Notes — Riya Sharma</div>
          <textarea style={{ width:'100%', height:120, border:'1px solid #EAECF4', borderRadius:8, padding:10, fontSize:12, fontFamily:'Poppins,sans-serif', resize:'none', boxSizing:'border-box', marginBottom:10 }} defaultValue="Session 3: Discussed progress on stakeholder mapping exercise. Riya showed strong self-awareness around her communication style gaps. Set 2 new actions: (1) structured 1:1 with CFO, (2) attend leadership workshop..."></textarea>
          <div style={{ display:'flex', gap:8 }}>
            <button style={fStyles.secBtn}>Mark Private</button>
            <button style={fStyles.primBtn}>Save Notes</button>
          </div>
        </FCard>
        <FCard>
          <div style={{ fontWeight:700, fontSize:14, color:'#1C2551', marginBottom:14 }}>ALS Workspace</div>
          {[{team:'Alpha',challenge:'Driving digital adoption in legacy teams',update:'Posted 2 new peer commentaries'},{team:'Beta',challenge:'Cross-functional alignment during re-org',update:'Awaiting 3 responses'}].map((als,i) => (
            <div key={i} style={{ padding:'12px 0', borderBottom:'1px solid #EAECF4' }}>
              <div style={{ display:'flex', justifyContent:'space-between' }}>
                <span style={{ fontWeight:600, fontSize:13, color:'#1C2551' }}>Team {als.team}</span>
                <FBadge label="Active" color="#22c55e" />
              </div>
              <div style={{ fontSize:11, color:'#8b90a7', margin:'4px 0' }}>{als.challenge}</div>
              <div style={{ fontSize:11, color:'#6B73BF' }}>{als.update}</div>
            </div>
          ))}
        </FCard>
      </div>
      {selectedParticipant && <CoachingTimelinePanel participant={selectedParticipant} onClose={()=>setSelectedParticipant(null)} />}
    </div>
  );
}

