function MobileSAOrgs({ onConfig }) {
  const [showWizard, setShowWizard] = React.useState(false);
  const [success, setSuccess] = React.useState(null);
  const [orgs, setOrgs] = React.useState([
    { name:'Mahindra Group', plan:'Enterprise', users:240, health:98, status:'Active' },
    { name:'Tata Sons', plan:'Enterprise', users:180, health:95, status:'Active' },
    { name:'HDFC Bank', plan:'Pro', users:90, health:87, status:'Active' },
    { name:'Infosys Ltd.', plan:'Pro', users:60, health:74, status:'Trial' },
    { name:'Wipro Ltd.', plan:'Starter', users:24, health:91, status:'Active' },
  ]);

  function handleComplete(form) {
    setOrgs(prev => [...prev, { name:form.name, plan:form.plan, users:form.seats, health:100, status:'Active' }]);
    setSuccess(form);
    setShowWizard(false);
  }

  return (
    <div style={{ ...mPage, position:'relative' }}>
      <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:10 }}>
        {[[orgs.length.toString(),'Organizations','#1C2551',{sections:[{title:'BY PLAN',rows:[{label:'Enterprise',value:'2',bar:40,color:'#1C2551'},{label:'Pro',value:'2',bar:40,color:'#EF4E24'},{label:'Starter',value:'1',bar:20,color:'#6B73BF'}]}]}],['594','Active Users','#EF4E24',{sections:[{title:'BY ORG',rows:[{label:'Mahindra Group',value:'240',bar:100,color:'#EF4E24'},{label:'Tata Sons',value:'180',bar:75,color:'#1C2551'},{label:'HDFC Bank',value:'90',bar:37,color:'#6B73BF'},{label:'Infosys',value:'60',bar:25,color:'#22c55e'},{label:'Wipro',value:'24',bar:10}]}]}],['99.97%','Uptime','#22c55e',{sections:[{title:'SERVICES',rows:[{label:'API Gateway',value:'99.99%',bar:99,color:'#22c55e'},{label:'Video Bridge',value:'97.2%',bar:97,color:'#EF4E24'},{label:'Database',value:'100%',bar:100,color:'#22c55e'}]}]}],['142K','API Calls','#6B73BF',{sections:[{title:'BY ENDPOINT',rows:[{label:'Content API',value:'58K',bar:40,color:'#6B73BF'},{label:'Auth API',value:'34K',bar:23,color:'#1C2551'},{label:'AI/ML API',value:'28K',bar:19,color:'#EF4E24'}]}]}]].map(([v,l,c,det],i) => (
          <div key={i} onClick={()=>showStatDetail({label:l,value:v,color:c,...det})} style={{ ...mCard, padding:'12px 10px', textAlign:'center', cursor:'pointer' }}>
            <div style={{ fontSize:i>1?13:20, fontWeight:800, color:c }}>{v}</div>
            <div style={{ fontSize:10, color:'#8b90a7', marginTop:2 }}>{l}</div>
            <div style={{ fontSize:8, color:'#8b90a7', marginTop:3, fontWeight:600 }}>TAP →</div>
          </div>
        ))}
      </div>
      {success && (
        <div style={{ ...mCard, background:'rgba(34,197,94,0.06)', border:'1px solid rgba(34,197,94,0.25)', padding:'12px 14px' }}>
          <div style={{ display:'flex', gap:10, alignItems:'flex-start' }}>
            <span style={{ fontSize:18 }}>🎉</span>
            <div style={{ flex:1 }}>
              <div style={{ fontSize:12, fontWeight:700, color:'#1C2551' }}>{success.name} onboarded!</div>
              <div style={{ fontSize:10, color:'#8b90a7', marginTop:2 }}>Email sent · {success.plan} · {success.seats} seats</div>
            </div>
            <button onClick={()=>setSuccess(null)} style={{ fontSize:14, color:'#8b90a7', background:'none', border:'none', cursor:'pointer' }}>✕</button>
          </div>
        </div>
      )}
      <button onClick={()=>setShowWizard(true)} style={{ width:'100%', padding:'11px', background:'#EF4E24', border:'none', borderRadius:10, color:'#fff', fontSize:13, fontWeight:700, fontFamily:'Poppins,sans-serif', cursor:'pointer' }}>+ New Organization</button>
      {orgs.map((o,i) => (
        <div key={i} style={mCard}>
          <div style={{ display:'flex', alignItems:'center', gap:12 }}>
            <div style={{ width:36, height:36, borderRadius:10, background:'#1C2551', color:'#fff', fontWeight:700, fontSize:14, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>{o.name[0]}</div>
            <div style={{ flex:1 }}>
              <div style={{ display:'flex', justifyContent:'space-between', marginBottom:3 }}>
                <span style={{ fontSize:12, fontWeight:600, color:'#1C2551' }}>{o.name}</span>
                <span style={{ fontSize:9, background:o.status==='Trial'?'rgba(239,78,36,0.1)':'rgba(34,197,94,0.1)', color:o.status==='Trial'?'#EF4E24':'#22c55e', borderRadius:10, padding:'2px 7px', fontWeight:700 }}>{o.status}</span>
              </div>
              <div style={{ display:'flex', gap:8, alignItems:'center', marginBottom:8 }}>
                <span style={{ fontSize:10, color:'#8b90a7' }}>{o.plan} · {o.users} users</span>
                <div style={{ flex:1, height:4, background:'#F0F1F7', borderRadius:99 }}><div style={{ height:'100%', width:`${o.health}%`, background:o.health>90?'#22c55e':'#EF4E24', borderRadius:99 }}></div></div>
                <span style={{ fontSize:10, fontWeight:700, color:'#1C2551' }}>{o.health}%</span>
              </div>
              <button onClick={()=>onConfig&&onConfig(o)} style={{ padding:'5px 12px', background:'#F5F7FB', border:'1px solid #EAECF4', borderRadius:7, fontSize:11, fontWeight:600, color:'#1C2551', cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>Config ›</button>
            </div>
          </div>
        </div>
      ))}
      {showWizard && <OrgOnboardWizard mobile={true} onClose={()=>setShowWizard(false)} onComplete={handleComplete} />}
    </div>
  );
}

