function MobileParticipant360() {
  const competencies = ['Strategic Thinking','Executive Presence','Stakeholder Influence','Change Leadership','Decision Making'];
  const self = [3.8,4.2,3.5,3.0,4.0], others = [3.2,3.6,3.9,3.4,3.7];
  const W=260,H=260,cx=130,cy=130,r=95,n=competencies.length;
  const toXY=(i,val)=>{const a=(i/n)*2*Math.PI-Math.PI/2,rad=(val/5)*r;return{x:cx+rad*Math.cos(a),y:cy+rad*Math.sin(a)};};
  const labelXY=i=>{const a=(i/n)*2*Math.PI-Math.PI/2;return{x:cx+(r+22)*Math.cos(a),y:cy+(r+22)*Math.sin(a)};};
  return (
    <div style={mPage}>
      <div style={{ ...mCard, alignItems:'center', display:'flex', flexDirection:'column' }}>
        <div style={{ fontSize:12, fontWeight:700, color:'#1C2551', marginBottom:8, alignSelf:'flex-start' }}>Competency Radar</div>
        <svg width={W} height={H} style={{ maxWidth:'100%' }}>
          {[1,2,3,4,5].map(lvl=>{const pts=Array.from({length:n}).map((_,i)=>{const a=(i/n)*2*Math.PI-Math.PI/2,rad=(lvl/5)*r;return `${cx+rad*Math.cos(a)},${cy+rad*Math.sin(a)}`;}).join(' ');return <polygon key={lvl} points={pts} fill="none" stroke="#EAECF4" strokeWidth="1" />;})}
          {Array.from({length:n}).map((_,i)=>{const a=(i/n)*2*Math.PI-Math.PI/2;return <line key={i} x1={cx} y1={cy} x2={cx+r*Math.cos(a)} y2={cy+r*Math.sin(a)} stroke="#EAECF4" strokeWidth="1" />;})}
          <polygon points={others.map((_,i)=>{const p=toXY(i,others[i]);return `${p.x},${p.y}`;}).join(' ')} fill="rgba(28,37,81,0.12)" stroke="#1C2551" strokeWidth="2" />
          <polygon points={self.map((_,i)=>{const p=toXY(i,self[i]);return `${p.x},${p.y}`;}).join(' ')} fill="rgba(239,78,36,0.15)" stroke="#EF4E24" strokeWidth="2" />
          {competencies.map((c,i)=>{const lp=labelXY(i);return <text key={i} x={lp.x} y={lp.y} textAnchor="middle" dominantBaseline="middle" fontSize="9" fill="#8b90a7">{c.split(' ')[0]}</text>;})}
        </svg>
        <div style={{ display:'flex', gap:14, justifyContent:'center' }}>
          <div style={{ display:'flex', alignItems:'center', gap:4, fontSize:10 }}><span style={{ width:12,height:3,background:'#EF4E24',display:'inline-block',borderRadius:2 }}></span>Self</div>
          <div style={{ display:'flex', alignItems:'center', gap:4, fontSize:10 }}><span style={{ width:12,height:3,background:'#1C2551',display:'inline-block',borderRadius:2 }}></span>Others</div>
        </div>
      </div>
      <div style={{ ...mCard, background:'rgba(239,78,36,0.03)', border:'1px solid rgba(239,78,36,0.15)' }}>
        <div style={{ fontSize:10, fontWeight:700, color:'#EF4E24', marginBottom:8 }}>✦ AI Narrative</div>
        <div style={{ fontSize:11, color:'#1C2551', lineHeight:1.6 }}><strong>Strengths:</strong> Executive Presence. <strong>Blind Spots:</strong> Self-rating on Stakeholder Influence is lower than others perceive. <strong>Focus:</strong> Change Leadership.</div>
      </div>
      <div style={mCard}>
        <div style={{ fontSize:12, fontWeight:700, color:'#1C2551', marginBottom:10 }}>Rater Status</div>
        {[{name:'Manager – Vikram Singh',status:'Submitted'},{name:'Peer – Neha Iyer',status:'Submitted'},{name:'Peer – Arjun Das',status:'Pending'},{name:'Direct Report – Meera K.',status:'Pending'}].map((r,i) => (
          <div key={i} style={{ display:'flex', justifyContent:'space-between', padding:'8px 0', borderBottom:'1px solid #EAECF4' }}>
            <span style={{ fontSize:11, color:'#1C2551', flex:1 }}>{r.name}</span>
            <span style={{ fontSize:9, background:r.status==='Submitted'?'rgba(34,197,94,0.1)':'rgba(239,78,36,0.1)', color:r.status==='Submitted'?'#22c55e':'#EF4E24', borderRadius:10, padding:'2px 7px', fontWeight:700 }}>{r.status}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

