// ─── New PM Screens ───────────────────────────────────────────────────────────
function MobilePMDesign() {
  const [view, setView] = React.useState('list');
  const [selectedProgram, setSelectedProgram] = React.useState(null);
  const [statusFilter, setStatusFilter] = React.useState('All');
  const [programs] = React.useState([
    { id:1, name:'Leadership Accelerator – Batch 7', status:'Active',    phase:'Phase 3: Classroom',   enrolled:32, health:82,  color:'#EF4E24' },
    { id:2, name:'Senior Manager Fast Track',        status:'Active',    phase:'Phase 2: Pre-Work',    enrolled:24, health:71,  color:'#1C2551' },
    { id:3, name:'Women in Leadership 2026',         status:'Active',    phase:'Phase 4: Post Class.', enrolled:18, health:91,  color:'#6B73BF' },
    { id:4, name:'Leadership Accelerator – Batch 6', status:'Delivered', phase:'Completed',            enrolled:30, health:100, color:'#22c55e' },
    { id:5, name:'Executive Presence Workshop',      status:'Upcoming',  phase:'Not Started',          enrolled:20, health:0,   color:'#EF4E24' },
    { id:6, name:'Digital Leaders Program',          status:'Draft',     phase:'Design Phase',         enrolled:0,  health:0,   color:'#8b90a7' },
  ]);
  const filters = ['All','Active','Upcoming','Delivered','Draft'];
  const statusColors = { Active:'#22c55e', Upcoming:'#EF4E24', Delivered:'#1C2551', Draft:'#8b90a7' };
  const filtered = programs.filter(p=>statusFilter==='All'||p.status===statusFilter);

  if (view === 'studio') return <MobilePMDesignStudio program={selectedProgram} onBack={()=>setView('list')} />;

  return (
    <div style={mPage}>
      <div style={{ display:'flex', gap:6, overflowX:'auto', paddingBottom:2 }}>
        {filters.map(f=>(
          <button key={f} onClick={()=>setStatusFilter(f)} style={{ flexShrink:0, padding:'5px 12px', border:`1.5px solid ${statusFilter===f?'#EF4E24':'#EAECF4'}`, borderRadius:16, background:statusFilter===f?'rgba(239,78,36,0.08)':'#fff', color:statusFilter===f?'#EF4E24':'#8b90a7', fontSize:11, fontWeight:statusFilter===f?700:400, cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>{f}</button>
        ))}
      </div>
      <button onClick={()=>{ setSelectedProgram({id:Date.now(),name:'New Program',color:'#EF4E24'}); setView('studio'); }} style={{ width:'100%', padding:'11px', background:'#EF4E24', border:'none', borderRadius:10, color:'#fff', fontSize:13, fontWeight:700, fontFamily:'Poppins,sans-serif', cursor:'pointer' }}>+ New Program Design</button>
      {filtered.map(prog=>(
        <div key={prog.id} onClick={()=>{ setSelectedProgram(prog); setView('studio'); }} style={{ ...mCard, cursor:'pointer' }}>
          <div style={{ display:'flex', alignItems:'center', gap:10, marginBottom:8 }}>
            <div style={{ width:32, height:32, borderRadius:8, background:prog.color, color:'#fff', fontWeight:800, fontSize:13, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>{prog.name[0]}</div>
            <div style={{ flex:1 }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start' }}>
                <span style={{ fontSize:12, fontWeight:700, color:'#1C2551', flex:1, paddingRight:8, lineHeight:1.3 }}>{prog.name}</span>
                <span style={{ fontSize:9, background:`${statusColors[prog.status]}14`, color:statusColors[prog.status], borderRadius:10, padding:'2px 7px', fontWeight:700, flexShrink:0 }}>{prog.status}</span>
              </div>
              <div style={{ fontSize:10, color:'#6B73BF', fontWeight:600, marginTop:2 }}>{prog.phase}</div>
            </div>
          </div>
          {prog.enrolled > 0 && (
            <div>
              <div style={{ display:'flex', justifyContent:'space-between', marginBottom:4 }}>
                <span style={{ fontSize:10, color:'#8b90a7' }}>{prog.enrolled} enrolled</span>
                <span style={{ fontSize:10, fontWeight:700, color:prog.health>80?'#22c55e':prog.health>0?'#EF4E24':'#D0D3E0' }}>{prog.health}%</span>
              </div>
              <div style={{ height:4, background:'#F0F1F7', borderRadius:99 }}><div style={{ height:'100%', width:`${prog.health}%`, background:prog.health>80?'#22c55e':'#EF4E24', borderRadius:99 }}></div></div>
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

function MobilePMDesignStudio({ program, onBack }) {
  const prog = program || { name:'New Program', color:'#EF4E24' };
  const [phases, setPhases] = React.useState([
    {phase:'Phase 0',title:'Pre-Enrolment',weeks:'Wk -4 to -2',color:'#6B73BF',activities:['Nomination','Enrollment','Welcome Email']},
    {phase:'Phase 1',title:'Orientation',weeks:'Wk -1',color:'#1C2551',activities:['Welcome Session','Cohort Intros','Norm-Setting']},
    {phase:'Phase 2',title:'Pre-Work',weeks:'Wk 1–4',color:'#EF4E24',activities:['Self-Paced Modules','Baseline Assessment']},
    {phase:'Phase 3',title:'Classroom',weeks:'Wk 5–6',color:'#1C2551',activities:['Instructor-Led Sessions','Guest Speakers']},
    {phase:'Phase 4',title:'Post Classroom',weeks:'Wk 7–10',color:'#6B73BF',activities:['Application Projects','Reflection Journal']},
    {phase:'Phase 5',title:'Group Coaching',weeks:'Wk 11–16',color:'#EF4E24',activities:['Cohort Circles','ALS Facilitation']},
    {phase:'Phase 6',title:'Capstone',weeks:'Wk 17–20',color:'#1C2551',activities:['Team Challenge','Panel Review']},
    {phase:'Phase 7',title:'Post Program',weeks:'30/60/90 Days',color:'#6B73BF',activities:['L4 Impact','Alumni Network']},
  ]);
  const [addModal, setAddModal] = React.useState(null);
  const [preview, setPreview] = React.useState(false);
  const [draftSaved, setDraftSaved] = React.useState(false);
  const [publishFlow, setPublishFlow] = React.useState(null);
  function handleAdd(idx, form) { setPhases(prev=>prev.map((p,i)=>i===idx?{...p,activities:[...p.activities,form.title]}:p)); }
  return (
    <div style={{ ...mPage, position:'relative' }}>
      <div style={{ ...mCard, padding:'10px 14px', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
        <button onClick={onBack} style={{ display:'flex', alignItems:'center', gap:5, background:'none', border:'none', cursor:'pointer', fontSize:12, fontWeight:600, color:'#8b90a7', fontFamily:'Poppins,sans-serif', padding:0 }}>← Programs</button>
        <span style={{ fontSize:11, fontWeight:700, color:'#1C2551' }}>{prog.name.split('–')[0].trim()}</span>
        <div style={{ display:'flex', gap:6 }}>
          {draftSaved && <span style={{ fontSize:9, color:'#22c55e', fontWeight:700 }}>✓ Saved</span>}
          <button onClick={()=>setPreview(true)} style={{ padding:'5px 8px', background:'#F5F7FB', border:'1px solid #EAECF4', borderRadius:7, color:'#1C2551', fontSize:9, fontWeight:600, cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>👁</button>
          <button onClick={()=>{ setDraftSaved(true); setTimeout(()=>setDraftSaved(false),2000); }} style={{ padding:'5px 8px', background:'#F5F7FB', border:'1px solid #EAECF4', borderRadius:7, color:'#1C2551', fontSize:9, fontWeight:600, cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>Draft</button>
          <button onClick={()=>setPublishFlow('confirm')} style={{ padding:'6px 10px', background:'#EF4E24', border:'none', borderRadius:7, color:'#fff', fontSize:9, fontWeight:700, fontFamily:'Poppins,sans-serif', cursor:'pointer' }}>Publish</button>
        </div>
      </div>
      {phases.map((p,i) => (
        <div key={i} style={{ ...mCard, padding:'12px 14px' }}>
          <div style={{ fontSize:10, fontWeight:700, color:p.color, letterSpacing:0.5, marginBottom:2 }}>{p.phase} · {p.weeks}</div>
          <div style={{ fontSize:13, fontWeight:700, color:'#1C2551', marginBottom:7 }}>{p.title}</div>
          <div style={{ display:'flex', flexWrap:'wrap', gap:5 }}>
            {p.activities.map((a,j) => (<span key={j} style={{ fontSize:9, background:`${p.color}12`, color:p.color, borderRadius:6, padding:'3px 8px', fontWeight:500 }}>{a}</span>))}
            <span onClick={()=>setAddModal(i)} style={{ fontSize:9, background:'#F5F7FB', color:'#8b90a7', borderRadius:6, padding:'3px 8px', border:'1px dashed #D0D3E0', cursor:'pointer' }}>+ Add</span>
          </div>
        </div>
      ))}
      {addModal !== null && (
        <AddActivityModal phase={phases[addModal]} mobile={true} onClose={()=>setAddModal(null)} onAdd={form=>handleAdd(addModal,form)} />
      )}
      {/* Mobile participant preview overlay */}
      {preview && (
        <div style={{ position:'absolute', inset:0, zIndex:300, background:'#fff', display:'flex', flexDirection:'column', overflow:'hidden' }}>
          <div style={{ background:'linear-gradient(135deg,#1C2551,#2d3a7c)', padding:'14px 16px', flexShrink:0 }}>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:10 }}>
              <div>
                <div style={{ fontSize:9, color:'rgba(255,255,255,0.5)', fontWeight:700, letterSpacing:1, marginBottom:4 }}>PARTICIPANT VIEW</div>
                <div style={{ fontSize:15, fontWeight:800, color:'#fff', marginBottom:2, lineHeight:1.3 }}>{prog.name.split('–')[0].trim()}</div>
                <div style={{ fontSize:10, color:'rgba(255,255,255,0.6)' }}>{phases.length} phases · {phases.reduce((n,p)=>n+p.activities.length,0)} activities</div>
              </div>
              <button onClick={()=>setPreview(false)} style={{ width:26,height:26,border:'1px solid rgba(255,255,255,0.2)',borderRadius:'50%',background:'rgba(255,255,255,0.1)',cursor:'pointer',fontSize:12,display:'flex',alignItems:'center',justifyContent:'center',color:'#fff' }}>✕</button>
            </div>
            {/* Mini timeline */}
            <div style={{ display:'flex', alignItems:'center', overflowX:'auto', gap:0 }}>
              {phases.map((p,i)=>(
                <React.Fragment key={i}>
                  <div style={{ display:'flex', flexDirection:'column', alignItems:'center', minWidth:40 }}>
                    <div style={{ width:22, height:22, borderRadius:'50%', background:i<3?p.color:'rgba(255,255,255,0.15)', border:`2px solid ${i<3?p.color:'rgba(255,255,255,0.3)'}`, display:'flex', alignItems:'center', justifyContent:'center', fontSize:8, fontWeight:800, color:'#fff' }}>{i}</div>
                  </div>
                  {i<phases.length-1&&<div style={{ flex:1, height:2, background:i<2?'rgba(255,255,255,0.4)':'rgba(255,255,255,0.1)', minWidth:8, marginBottom:4 }}></div>}
                </React.Fragment>
              ))}
            </div>
          </div>
          <div style={{ flex:1, overflowY:'auto', padding:'12px 14px', display:'flex', flexDirection:'column', gap:10, background:'#F5F7FB' }}>
            {phases.map((p,i)=>{
              const c=p.color||'#EF4E24';
              const rgb=[parseInt(c.slice(1,3),16),parseInt(c.slice(3,5),16),parseInt(c.slice(5,7),16)].join(',');
              return (
                <div key={i} style={{ background:'#fff', borderRadius:12, border:'1px solid #EAECF4' }}>
                  <div style={{ display:'flex', alignItems:'center', gap:10, padding:'10px 14px', borderBottom:'1px solid #EAECF4', background:`rgba(${rgb},0.06)`, borderRadius:'12px 12px 0 0' }}>
                    <div style={{ width:24, height:24, borderRadius:'50%', background:c, color:'#fff', fontWeight:800, fontSize:10, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>{i}</div>
                    <div style={{ flex:1 }}>
                      <div style={{ fontSize:11, fontWeight:700, color:'#1C2551' }}>{p.title}</div>
                      <div style={{ fontSize:9, color:'#8b90a7' }}>{p.weeks}</div>
                    </div>
                    <span style={{ fontSize:9, background:`rgba(${rgb},0.12)`, color:c, borderRadius:8, padding:'2px 7px', fontWeight:700 }}>{p.activities.length}</span>
                  </div>
                  <div style={{ padding:'10px 14px' }}>
                    <div style={{ fontSize:9, fontWeight:700, color:'#8b90a7', letterSpacing:0.4, marginBottom:6 }}>ACTIVITIES</div>
                    <div style={{ display:'flex', flexWrap:'wrap', gap:5 }}>
                      {p.activities.map((a,j)=>(
                        <span key={j} style={{ fontSize:9, background:`rgba(${rgb},0.09)`, color:c, borderRadius:10, padding:'3px 9px', fontWeight:600, border:`1px solid rgba(${rgb},0.25)` }}>{a}</span>
                      ))}
                    </div>
                  </div>
                </div>
              );
            })}
            <div style={{ padding:'10px 12px', background:'rgba(239,78,36,0.04)', border:'1px solid rgba(239,78,36,0.15)', borderRadius:10, fontSize:10, color:'#1C2551', lineHeight:1.6 }}>
              <strong>✦ AI-powered</strong> — this journey adapts to your learning pace and development goals.
            </div>
          </div>
          <div style={{ padding:'10px 14px', borderTop:'1px solid #EAECF4', background:'#fff', flexShrink:0 }}>
            <button onClick={()=>setPreview(false)} style={{ width:'100%', padding:'11px', background:'#EF4E24', border:'none', borderRadius:10, color:'#fff', fontSize:12, fontWeight:700, cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>Close Preview</button>
          </div>
        </div>
      )}
      {publishFlow==='confirm' && (
        <div style={{ position:'absolute', inset:0, zIndex:300, background:'rgba(28,37,81,0.5)', display:'flex', flexDirection:'column', justifyContent:'flex-end' }}>
          <div style={{ background:'#fff', borderRadius:'16px 16px 0 0', padding:20, display:'flex', flexDirection:'column', gap:12 }}>
            <div style={{ fontSize:14, fontWeight:700, color:'#1C2551' }}>Publish “{prog.name.split('–')[0].trim()}”?</div>
            {[['Phases defined',phases.length>=3],['Activities in all phases',phases.every(p=>p.activities.length>0)],['Name set',!!prog.name]].map(([label,done],i)=>(
              <div key={i} style={{ display:'flex', alignItems:'center', gap:8 }}>
                <div style={{ width:18, height:18, borderRadius:'50%', background:done?'#22c55e':'#f59e0b', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
                  <span style={{ color:'#fff', fontSize:10 }}>{done?'✓':'⚠'}</span>
                </div>
                <span style={{ fontSize:12, color:done?'#1C2551':'#8b90a7' }}>{label}</span>
              </div>
            ))}
            <div style={{ display:'flex', gap:8, marginTop:4 }}>
              <button onClick={()=>setPublishFlow(null)} style={{ flex:1, padding:'10px', background:'#fff', border:'1px solid #EAECF4', borderRadius:10, cursor:'pointer', fontSize:12, fontWeight:600, color:'#1C2551', fontFamily:'Poppins,sans-serif' }}>Cancel</button>
              <button onClick={()=>setPublishFlow('success')} style={{ flex:2, padding:'10px', background:'#EF4E24', border:'none', borderRadius:10, cursor:'pointer', fontSize:12, fontWeight:700, color:'#fff', fontFamily:'Poppins,sans-serif' }}>Confirm &amp; Publish 🚀</button>
            </div>
          </div>
        </div>
      )}
      {publishFlow==='success' && (
        <div style={{ position:'absolute', inset:0, zIndex:300, background:'rgba(28,37,81,0.5)', display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>
          <div style={{ background:'#fff', borderRadius:16, padding:'32px 24px', textAlign:'center', width:'100%' }}>
            <div style={{ fontSize:40, marginBottom:12 }}>🎉</div>
            <div style={{ fontSize:16, fontWeight:800, color:'#1C2551', marginBottom:8 }}>Program Published!</div>
            <div style={{ fontSize:12, color:'#8b90a7', marginBottom:16, lineHeight:1.6 }}><strong style={{ color:'#1C2551' }}>{prog.name.split('–')[0].trim()}</strong> is now live.</div>
            <button onClick={()=>{ setPublishFlow(null); onBack&&onBack(); }} style={{ width:'100%', padding:'11px', background:'#EF4E24', border:'none', borderRadius:10, cursor:'pointer', fontSize:12, fontWeight:700, color:'#fff', fontFamily:'Poppins,sans-serif' }}>Back to Programs →</button>
          </div>
        </div>
      )}
    </div>
  );
}

function MobilePMROI() {
  return (
    <div style={mPage}>
      <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:10 }}>
        {[['+26 pts','Competency Lift','#EF4E24'],['4.3/5.0','Manager Satisfaction','#1C2551'],['12','Impact Stories','#6B73BF'],['3.2x','Est. ROI','#22c55e']].map(([v,l,c],i) => (
          <div key={i} style={{ ...mCard, textAlign:'center', padding:'12px 8px' }}><div style={{ fontSize:18, fontWeight:800, color:c }}>{v}</div><div style={{ fontSize:9, color:'#8b90a7', marginTop:2 }}>{l}</div></div>
        ))}
      </div>
      <div style={{ ...mCard, background:'rgba(239,78,36,0.03)', border:'1px solid rgba(239,78,36,0.15)' }}>
        <div style={{ fontSize:10, fontWeight:700, color:'#EF4E24', marginBottom:8 }}>✦ AI ROI Narrative</div>
        <div style={{ fontSize:12, color:'#1C2551', lineHeight:1.6 }}>Participants showed a <strong>+26 pt average competency improvement</strong>. Manager satisfaction improved by 18%, with 12 impact stories. Estimated ROI: <strong>3.2x</strong> program investment.</div>
      </div>
      <div style={mCard}>
        <div style={{ fontSize:12, fontWeight:700, color:'#1C2551', marginBottom:10 }}>Competency Improvement</div>
        {[['Strategic Thinking',26],['Executive Presence',25],['Stakeholder Influence',14],['Change Leadership',28],['Decision Making',15]].map(([k,v],i) => (
          <div key={i} style={{ display:'flex', alignItems:'center', gap:8, marginBottom:9 }}>
            <span style={{ fontSize:11, color:'#1C2551', flex:1 }}>{k}</span>
            <div style={{ width:80, height:5, background:'#F0F1F7', borderRadius:99 }}><div style={{ height:'100%', width:`${v*2.5}%`, background:'#EF4E24', borderRadius:99 }}></div></div>
            <span style={{ fontSize:11, fontWeight:700, color:'#22c55e', width:28, textAlign:'right' }}>+{v}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

// ─── New SA Screens ───────────────────────────────────────────────────────────
