const SEV_COLORS = { info:'#1C2551', warning:'#f59e0b', error:'#ef4444', success:'#22c55e' };
const SEV_BG     = { info:'rgba(28,37,81,0.07)', warning:'rgba(245,158,11,0.1)', error:'rgba(239,68,68,0.1)', success:'rgba(34,197,94,0.1)' };
const CAT_COLORS = { Admin:'#1C2551', Auth:'#EF4E24', Submission:'#6B73BF', Program:'#EF4E24', Grading:'#6B73BF', System:'#8b90a7', Comms:'#22c55e', Session:'#1C2551' };

function SAuditLog() {
  const [search, setSearch]       = React.useState('');
  const [catFilter, setCatFilter] = React.useState('All');
  const [sevFilter, setSevFilter] = React.useState('All');
  const [orgFilter, setOrgFilter] = React.useState('All');
  const [expanded, setExpanded]   = React.useState(null);
  const [dateFrom, setDateFrom]   = React.useState('');
  const [dateTo, setDateTo]       = React.useState('');

  const categories = ['All','Admin','Auth','Submission','Program','Grading','System','Comms','Session'];
  const severities = ['All','info','warning','error','success'];
  const orgs       = ['All',...new Set(AUDIT_ENTRIES.map(e=>e.org))];

  const filtered = AUDIT_ENTRIES.filter(e => {
    if (catFilter!=='All' && e.category!==catFilter) return false;
    if (sevFilter!=='All' && e.severity!==sevFilter) return false;
    if (orgFilter!=='All' && e.org!==orgFilter) return false;
    if (search && ![e.user,e.action,e.detail,e.org].join(' ').toLowerCase().includes(search.toLowerCase())) return false;
    return true;
  });

  const stats = {
    total: AUDIT_ENTRIES.length,
    errors: AUDIT_ENTRIES.filter(e=>e.severity==='error').length,
    warnings: AUDIT_ENTRIES.filter(e=>e.severity==='warning').length,
    admins: AUDIT_ENTRIES.filter(e=>e.category==='Admin').length,
  };

  return (
    <div style={saStyles.page}>
      {/* Stats */}
      <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:14 }}>
        {[{l:'Total Events (Today)',v:stats.total.toString(),c:'#1C2551'},{l:'Errors',v:stats.errors.toString(),c:'#ef4444'},{l:'Warnings',v:stats.warnings.toString(),c:'#f59e0b'},{l:'Admin Actions',v:stats.admins.toString(),c:'#EF4E24'}].map(({l,v,c},i)=>(
          <SACard key={i}><div style={{ fontSize:11, color:'#8b90a7', marginBottom:5 }}>{l}</div><div style={{ fontSize:26, fontWeight:800, color:c }}>{v}</div></SACard>
        ))}
      </div>
      {/* Filters */}
      <SACard style={{ padding:'14px 18px' }}>
        <div style={{ display:'flex', gap:12, flexWrap:'wrap', alignItems:'center' }}>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search user, action, detail…" style={{ flex:1, minWidth:200, border:'1px solid #EAECF4', borderRadius:8, padding:'8px 12px', fontSize:13, fontFamily:'Poppins,sans-serif', color:'#1C2551', boxSizing:'border-box' }} />
          <select value={catFilter} onChange={e=>setCatFilter(e.target.value)} style={{ border:'1px solid #EAECF4', borderRadius:8, padding:'8px 12px', fontSize:12, fontFamily:'Poppins,sans-serif', color:'#1C2551', cursor:'pointer' }}>
            {categories.map(c=><option key={c} value={c}>{c==='All'?'All Categories':c}</option>)}
          </select>
          <select value={sevFilter} onChange={e=>setSevFilter(e.target.value)} style={{ border:'1px solid #EAECF4', borderRadius:8, padding:'8px 12px', fontSize:12, fontFamily:'Poppins,sans-serif', color:'#1C2551', cursor:'pointer' }}>
            {severities.map(s=><option key={s} value={s}>{s==='All'?'All Severities':s.charAt(0).toUpperCase()+s.slice(1)}</option>)}
          </select>
          <select value={orgFilter} onChange={e=>setOrgFilter(e.target.value)} style={{ border:'1px solid #EAECF4', borderRadius:8, padding:'8px 12px', fontSize:12, fontFamily:'Poppins,sans-serif', color:'#1C2551', cursor:'pointer' }}>
            {orgs.map(o=><option key={o} value={o}>{o==='All'?'All Orgs':o}</option>)}
          </select>
          <button style={{ padding:'8px 16px', background:'#EF4E24', border:'none', borderRadius:8, fontSize:12, fontWeight:700, color:'#fff', cursor:'pointer', fontFamily:'Poppins,sans-serif', whiteSpace:'nowrap' }}>⬇ Export CSV</button>
        </div>
        <div style={{ fontSize:11, color:'#8b90a7', marginTop:10 }}>Showing {filtered.length} of {AUDIT_ENTRIES.length} events</div>
      </SACard>
      {/* Log table */}
      <SACard style={{ padding:0, overflow:'hidden' }}>
        <table style={{ width:'100%', borderCollapse:'collapse' }}>
          <thead>
            <tr style={{ background:'#F5F7FB' }}>
              {['Timestamp','User','Category','Action','Organization','Severity',''].map(h=>(
                <th key={h} style={{ padding:'11px 14px', textAlign:'left', fontSize:11, fontWeight:700, color:'#8b90a7', letterSpacing:0.5, whiteSpace:'nowrap' }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filtered.map(e=>(
              <React.Fragment key={e.id}>
                <tr onClick={()=>setExpanded(expanded===e.id?null:e.id)} style={{ borderTop:'1px solid #EAECF4', cursor:'pointer', background:expanded===e.id?'rgba(239,78,36,0.03)':'#fff' }}>
                  <td style={{ padding:'11px 14px', fontSize:11, color:'#8b90a7', whiteSpace:'nowrap', fontFamily:'monospace' }}>{e.ts}</td>
                  <td style={{ padding:'11px 14px' }}>
                    <div style={{ fontSize:12, fontWeight:600, color:'#1C2551' }}>{e.user}</div>
                    <div style={{ fontSize:10, color:'#8b90a7' }}>{e.role}</div>
                  </td>
                  <td style={{ padding:'11px 14px' }}>
                    <span style={{ fontSize:10, background:SEV_BG[CAT_COLORS[e.category]?'info':'info'], color:CAT_COLORS[e.category]||'#8b90a7', background:`${CAT_COLORS[e.category]||'#8b90a7'}18`, borderRadius:10, padding:'2px 8px', fontWeight:700 }}>{e.category}</span>
                  </td>
                  <td style={{ padding:'11px 14px', fontSize:13, fontWeight:600, color:'#1C2551' }}>{e.action}</td>
                  <td style={{ padding:'11px 14px', fontSize:12, color:'#8b90a7' }}>{e.org}</td>
                  <td style={{ padding:'11px 14px' }}>
                    <span style={{ fontSize:10, background:SEV_BG[e.severity], color:SEV_COLORS[e.severity], borderRadius:10, padding:'2px 8px', fontWeight:700 }}>{e.severity}</span>
                  </td>
                  <td style={{ padding:'11px 14px', fontSize:14, color:'#8b90a7' }}>{expanded===e.id?'▲':'▼'}</td>
                </tr>
                {expanded===e.id && (
                  <tr style={{ borderTop:'1px solid #EAECF4', background:'rgba(239,78,36,0.02)' }}>
                    <td colSpan={7} style={{ padding:'12px 14px 14px 48px' }}>
                      <div style={{ display:'flex', gap:24, flexWrap:'wrap' }}>
                        <div><div style={{ fontSize:10, fontWeight:700, color:'#8b90a7', marginBottom:4 }}>EVENT ID</div><div style={{ fontFamily:'monospace', fontSize:12, color:'#1C2551' }}>{e.id}</div></div>
                        <div><div style={{ fontSize:10, fontWeight:700, color:'#8b90a7', marginBottom:4 }}>TIMESTAMP</div><div style={{ fontSize:12, color:'#1C2551' }}>{e.ts}</div></div>
                        <div style={{ flex:1, minWidth:260 }}><div style={{ fontSize:10, fontWeight:700, color:'#8b90a7', marginBottom:4 }}>DETAIL</div><div style={{ fontSize:12, color:'#1C2551', lineHeight:1.6 }}>{e.detail}</div></div>
                        <div style={{ display:'flex', gap:8 }}>
                          <button style={{ padding:'5px 12px', background:'#F5F7FB', border:'1px solid #EAECF4', borderRadius:7, fontSize:11, color:'#1C2551', cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>Copy ID</button>
                          {e.severity==='error'&&<button style={{ padding:'5px 12px', background:'rgba(239,68,68,0.08)', border:'1px solid rgba(239,68,68,0.2)', borderRadius:7, fontSize:11, color:'#ef4444', cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>View Incident</button>}
                        </div>
                      </div>
                    </td>
                  </tr>
                )}
              </React.Fragment>
            ))}
          </tbody>
        </table>
        {filtered.length===0 && (
          <div style={{ padding:'40px', textAlign:'center', color:'#8b90a7', fontSize:13 }}>No events match your filters.</div>
        )}
      </SACard>
    </div>
  );
}

function MobileSAAuditLog() {
  const [search, setSearch]       = React.useState('');
  const [catFilter, setCatFilter] = React.useState('All');
  const [expanded, setExpanded]   = React.useState(null);
  const categories = ['All','Admin','Auth','Submission','System','Comms'];
  const filtered = AUDIT_ENTRIES.filter(e => {
    if (catFilter!=='All' && e.category!==catFilter) return false;
    if (search && ![e.user,e.action,e.org].join(' ').toLowerCase().includes(search.toLowerCase())) return false;
    return true;
  });
  return (
    <div style={mPage}>
      <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:10 }}>
        {[[AUDIT_ENTRIES.length.toString(),'Events Today','#1C2551'],[AUDIT_ENTRIES.filter(e=>e.severity==='error'||e.severity==='warning').length.toString(),'Alerts','#EF4E24']].map(([v,l,c],i)=>(
          <div key={i} style={{ ...mCard, textAlign:'center', padding:'12px 8px' }}><div style={{ fontSize:22, fontWeight:800, color:c }}>{v}</div><div style={{ fontSize:10, color:'#8b90a7', marginTop:2 }}>{l}</div></div>
        ))}
      </div>
      <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search user, action…" style={{ width:'100%', border:'1px solid #EAECF4', borderRadius:8, padding:'9px 12px', fontSize:12, fontFamily:'Poppins,sans-serif', color:'#1C2551', boxSizing:'border-box' }} />
      <div style={{ display:'flex', gap:6, overflowX:'auto', paddingBottom:2 }}>
        {categories.map(c=><button key={c} onClick={()=>setCatFilter(c)} style={{ flexShrink:0, padding:'5px 12px', border:`1.5px solid ${catFilter===c?'#EF4E24':'#EAECF4'}`, borderRadius:16, background:catFilter===c?'rgba(239,78,36,0.08)':'#fff', color:catFilter===c?'#EF4E24':'#8b90a7', fontSize:11, fontWeight:catFilter===c?700:400, cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>{c}</button>)}
      </div>
      <div style={{ fontSize:10, color:'#8b90a7' }}>{filtered.length} of {AUDIT_ENTRIES.length} events</div>
      {filtered.map(e=>(
        <div key={e.id} onClick={()=>setExpanded(expanded===e.id?null:e.id)} style={{ ...mCard, padding:'12px 14px', cursor:'pointer', background:expanded===e.id?'rgba(239,78,36,0.02)':'#fff', border:e.severity==='error'?'1px solid rgba(239,68,68,0.25)':e.severity==='warning'?'1px solid rgba(245,158,11,0.25)':'1px solid #EAECF4' }}>
          <div style={{ display:'flex', gap:10, alignItems:'flex-start' }}>
            <div style={{ width:8, height:8, borderRadius:'50%', background:SEV_COLORS[e.severity], flexShrink:0, marginTop:5 }}></div>
            <div style={{ flex:1 }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:3 }}>
                <span style={{ fontSize:12, fontWeight:700, color:'#1C2551', flex:1, paddingRight:8, lineHeight:1.3 }}>{e.action}</span>
                <span style={{ fontSize:9, color:'#8b90a7', flexShrink:0 }}>{e.ts.split(' ')[1]}</span>
              </div>
              <div style={{ fontSize:10, color:'#8b90a7', marginBottom:3 }}>{e.user} · {e.org}</div>
              <div style={{ display:'flex', gap:6 }}>
                <span style={{ fontSize:9, background:`${CAT_COLORS[e.category]||'#8b90a7'}15`, color:CAT_COLORS[e.category]||'#8b90a7', borderRadius:8, padding:'2px 7px', fontWeight:700 }}>{e.category}</span>
                <span style={{ fontSize:9, background:SEV_BG[e.severity], color:SEV_COLORS[e.severity], borderRadius:8, padding:'2px 7px', fontWeight:700 }}>{e.severity}</span>
              </div>
              {expanded===e.id && (
                <div style={{ marginTop:10, padding:'10px 12px', background:'#F5F7FB', borderRadius:8, fontSize:11, color:'#1C2551', lineHeight:1.6 }}>
                  {e.detail}
                  <div style={{ marginTop:6, fontSize:9, color:'#8b90a7', fontFamily:'monospace' }}>ID: {e.id} · {e.ts}</div>
                </div>
              )}
            </div>
            <span style={{ fontSize:12, color:'#8b90a7', flexShrink:0, marginTop:2 }}>{expanded===e.id?'▲':'▼'}</span>
          </div>
        </div>
      ))}
      {filtered.length===0 && <div style={{ ...mCard, textAlign:'center', color:'#8b90a7', fontSize:12, padding:'24px' }}>No events match your filters.</div>}
      <button style={{ padding:'11px', background:'#EF4E24', border:'none', borderRadius:10, color:'#fff', fontSize:12, fontWeight:700, cursor:'pointer', fontFamily:'Poppins,sans-serif', width:'100%' }}>⬇ Export CSV</button>
    </div>
  );
}

