function SASurveys({ orgFilter }) {
  const [typeFilter, setTypeFilter] = React.useState('All');
  const data = SA_SURVEY_DATA.filter(s => (!orgFilter||orgFilter==='All Orgs'||s.org===orgFilter) && (typeFilter==='All'||s.type===typeFilter));
  const types = ['All',...new Set(SA_SURVEY_DATA.map(s=>s.type))];
  const avgCompletion = data.length ? Math.round(data.reduce((a,s)=>a+s.completion,0)/data.length) : 0;
  const totalResponses = data.reduce((a,s)=>a+s.responses,0);
  return (
    <div style={{ padding:24, display:'flex', flexDirection:'column', gap:16, overflowY:'auto', fontFamily:'Poppins,sans-serif' }}>
      <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:14 }}>
        {[['Active Surveys',data.filter(s=>s.status==='Active').length,'#1C2551'],['Total Responses',totalResponses,'#EF4E24'],['Avg Completion',avgCompletion+'%','#22c55e'],['Survey Types',types.length-1,'#6B73BF']].map(([l,v,c])=>(
          <div key={l} style={{ background:'#fff', borderRadius:12, border:'1px solid #EAECF4', padding:'16px 18px', boxShadow:'0 1px 4px rgba(28,37,81,0.06)' }}>
            <div style={{ fontSize:11, color:'#8b90a7', marginBottom:5 }}>{l}</div>
            <div style={{ fontSize:26, fontWeight:800, color:c }}>{v}</div>
          </div>
        ))}
      </div>
      <div style={{ display:'flex', gap:6, flexWrap:'wrap' }}>
        {types.map(t=>(
          <button key={t} onClick={()=>setTypeFilter(t)} style={{ padding:'6px 14px', border:'1px solid #EAECF4', borderRadius:8, background:typeFilter===t?'#1C2551':'#fff', color:typeFilter===t?'#fff':'#8b90a7', fontSize:11, fontWeight:typeFilter===t?700:400, cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>{t}</button>
        ))}
      </div>
      <div style={{ display:'flex', flexDirection:'column', gap:10 }}>
        {data.map((s,i)=>(
          <div key={i} style={{ background:'#fff', borderRadius:12, border:'1px solid #EAECF4', padding:'16px 18px', boxShadow:'0 1px 4px rgba(28,37,81,0.06)' }}>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:12 }}>
              <div>
                <div style={{ fontSize:13, fontWeight:700, color:'#1C2551', marginBottom:2 }}>{s.title}</div>
                <div style={{ fontSize:11, color:'#8b90a7' }}>{s.program} · {s.org} · Closes {s.closes}</div>
              </div>
              <div style={{ display:'flex', gap:8, alignItems:'center' }}>
                <span style={{ fontSize:9, background:s.status==='Active'?'rgba(34,197,94,0.1)':'rgba(107,115,191,0.1)', color:s.status==='Active'?'#22c55e':'#6B73BF', borderRadius:10, padding:'3px 8px', fontWeight:700 }}>{s.status.toUpperCase()}</span>
                <span style={{ fontSize:9, background:'rgba(28,37,81,0.08)', color:'#1C2551', borderRadius:10, padding:'3px 8px', fontWeight:700 }}>{s.type.toUpperCase()}</span>
              </div>
            </div>
            <div style={{ display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:12 }}>
              <div>
                <div style={{ fontSize:10, color:'#8b90a7', marginBottom:4 }}>Response Rate</div>
                <div style={{ display:'flex', alignItems:'center', gap:8 }}>
                  <div style={{ flex:1, height:6, background:'#F0F1F7', borderRadius:99 }}><div style={{ height:'100%', width:s.completion+'%', background:'#22c55e', borderRadius:99 }}></div></div>
                  <span style={{ fontSize:12, fontWeight:700, color:'#22c55e' }}>{s.completion}%</span>
                </div>
                <div style={{ fontSize:10, color:'#8b90a7', marginTop:2 }}>{s.responses} of {s.total} responded</div>
              </div>
              <div>
                <div style={{ fontSize:10, color:'#8b90a7', marginBottom:4 }}>Avg Score</div>
                <div style={{ fontSize:20, fontWeight:800, color:'#EF4E24' }}>{s.avgScore}</div>
                <div style={{ fontSize:10, color:'#8b90a7' }}>{s.type==='NPS'?'NPS score':'/5.0 avg'}</div>
              </div>
              <div style={{ display:'flex', gap:6, alignItems:'flex-end' }}>
                <button style={{ flex:1, padding:'7px 0', background:'#F5F7FB', border:'1px solid #EAECF4', borderRadius:7, fontSize:11, fontWeight:600, color:'#1C2551', cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>View Results</button>
                {s.status==='Active' && <button style={{ flex:1, padding:'7px 0', background:'#1C2551', border:'none', borderRadius:7, fontSize:11, fontWeight:700, color:'#fff', cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>Send Reminder</button>}
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

// ─── SA Discussions ───────────────────────────────────────────────────────────
const SA_DISCUSSION_DATA = [
  { id:'d1', title:'How are you applying the 5-forces model at work?', program:'Leadership Accelerator B7', org:'Mahindra Group', author:'Riya Sharma', replies:12, views:48, flagged:0, status:'active', lastActivity:'2h ago' },
  { id:'d2', title:'Sharing my stakeholder map — feedback welcome', program:'Leadership Accelerator B7', org:'Mahindra Group', author:'Vivek Kumar', replies:8, views:31, flagged:0, status:'active', lastActivity:'4h ago' },
  { id:'d3', title:'[FLAGGED] Inappropriate content — needs review', program:'Finance for Non-Finance', org:'Mahindra Group', author:'Unknown', replies:2, views:5, flagged:1, status:'flagged', lastActivity:'1d ago' },
  { id:'d4', title:'P&L Deep Dive — confusion on depreciation treatment', program:'Finance for Non-Finance', org:'Mahindra Group', author:'Deepak Bose', replies:6, views:22, flagged:0, status:'active', lastActivity:'6h ago' },
  { id:'d5', title:'Reflections on Session 2 — what hit different for you?', program:'Digital Leadership', org:'Infosys Ltd.', author:'Arjun Nair', replies:15, views:62, flagged:0, status:'active', lastActivity:'1h ago' },
  { id:'d6', title:'Networking thread — share your LinkedIn', program:'Women in Leadership', org:'Wipro Ltd.', author:'Meena Krishnan', replies:20, views:88, flagged:0, status:'pinned', lastActivity:'30m ago' },
];
function SADiscussions({ orgFilter }) {
  const [tab, setTab] = React.useState('all');
  const all = SA_DISCUSSION_DATA.filter(d => !orgFilter || orgFilter === 'All Orgs' || d.org === orgFilter);
  const filtered = tab==='all'?all:tab==='flagged'?all.filter(d=>d.status==='flagged'):tab==='pinned'?all.filter(d=>d.status==='pinned'):all.filter(d=>d.status==='active');
  const flagged = all.filter(d=>d.status==='flagged');
  function statusColor(s) { return s==='flagged'?'#ef4444':s==='pinned'?'#f59e0b':'#22c55e'; }
  return (
    <div style={{ padding:24, display:'flex', flexDirection:'column', gap:16, overflowY:'auto', fontFamily:'Poppins,sans-serif' }}>
      {flagged.length > 0 && (
        <div style={{ background:'rgba(239,68,68,0.06)', border:'1px solid rgba(239,68,68,0.2)', borderRadius:12, padding:'12px 18px', display:'flex', alignItems:'center', gap:12 }}>
          <span style={{ fontSize:20 }}>⚠</span>
          <div style={{ flex:1 }}>
            <div style={{ fontSize:12, fontWeight:700, color:'#ef4444' }}>{flagged.length} flagged discussion{flagged.length>1?'s':''} need review</div>
            <div style={{ fontSize:11, color:'#8b90a7' }}>Review and moderate or remove inappropriate content</div>
          </div>
          <button onClick={()=>setTab('flagged')} style={{ padding:'6px 14px', background:'#ef4444', border:'none', borderRadius:7, fontSize:11, fontWeight:700, color:'#fff', cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>Review Now</button>
        </div>
      )}
      <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:14 }}>
        {[['Total Threads',all.length,'#1C2551'],['Total Replies',all.reduce((a,d)=>a+d.replies,0),'#EF4E24'],['Flagged',flagged.length,'#ef4444'],['Pinned',all.filter(d=>d.status==='pinned').length,'#f59e0b']].map(([l,v,c])=>(
          <div key={l} style={{ background:'#fff', borderRadius:12, border:'1px solid #EAECF4', padding:'16px 18px', boxShadow:'0 1px 4px rgba(28,37,81,0.06)' }}>
            <div style={{ fontSize:11, color:'#8b90a7', marginBottom:5 }}>{l}</div>
            <div style={{ fontSize:26, fontWeight:800, color:c }}>{v}</div>
          </div>
        ))}
      </div>
      <div style={{ display:'flex', gap:6 }}>
        {[['all','All'],['active','Active'],['flagged','Flagged'],['pinned','Pinned']].map(([id,label])=>(
          <button key={id} onClick={()=>setTab(id)} style={{ padding:'7px 16px', border:'1px solid #EAECF4', borderRadius:8, background:tab===id?'#1C2551':'#fff', color:tab===id?'#fff':'#8b90a7', fontSize:12, fontWeight:tab===id?700:500, cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>{label}{id==='flagged'&&flagged.length>0?(' ('+flagged.length+')'):''}
          </button>
        ))}
      </div>
      <div style={{ display:'flex', flexDirection:'column', gap:8 }}>
        {filtered.map((d,i)=>(
          <div key={i} style={{ background:'#fff', borderRadius:12, border:'1px solid '+(d.status==='flagged'?'rgba(239,68,68,0.3)':'#EAECF4'), padding:'14px 18px', boxShadow:'0 1px 4px rgba(28,37,81,0.06)' }}>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', gap:12 }}>
              <div style={{ flex:1 }}>
                <div style={{ display:'flex', alignItems:'center', gap:8, marginBottom:4 }}>
                  <span style={{ fontSize:9, background:statusColor(d.status)+'18', color:statusColor(d.status), borderRadius:10, padding:'2px 7px', fontWeight:700 }}>{d.status.toUpperCase()}</span>
                  <span style={{ fontSize:10, color:'#8b90a7' }}>{d.program} · {d.org}</span>
                </div>
                <div style={{ fontSize:13, fontWeight:700, color:d.status==='flagged'?'#ef4444':'#1C2551', marginBottom:4 }}>{d.title}</div>
                <div style={{ fontSize:11, color:'#8b90a7' }}>by {d.author} · {d.replies} replies · {d.views} views · {d.lastActivity}</div>
              </div>
              <div style={{ display:'flex', gap:6, flexShrink:0 }}>
                {d.status==='flagged' && <button style={{ padding:'5px 12px', background:'rgba(239,68,68,0.08)', border:'1px solid rgba(239,68,68,0.2)', borderRadius:7, fontSize:11, fontWeight:700, color:'#ef4444', cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>Remove</button>}
                {d.status!=='flagged' && d.status!=='pinned' && <button style={{ padding:'5px 12px', background:'rgba(245,158,11,0.08)', border:'1px solid rgba(245,158,11,0.2)', borderRadius:7, fontSize:11, fontWeight:600, color:'#f59e0b', cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>Pin</button>}
                <button style={{ padding:'5px 12px', background:'#F5F7FB', border:'1px solid #EAECF4', borderRadius:7, fontSize:11, fontWeight:600, color:'#1C2551', cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>View</button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

