const SA_MARKETPLACE_PROGRAMS = [
  { id:'mp1', title:'Leadership Accelerator', provider:'fourward', duration:'20 weeks', format:'Blended', category:'Leadership', enrolled:450, rating:4.8, listed:true, featured:true, price:'₹85,000' },
  { id:'mp2', title:'Executive Presence Masterclass', provider:'fourward', duration:'8 weeks', format:'Virtual', category:'Communication', enrolled:280, rating:4.9, listed:true, featured:true, price:'₹45,000' },
  { id:'mp3', title:'Finance for Non-Finance Leaders', provider:'IIM-A Exec Ed', duration:'6 weeks', format:'Virtual', category:'Finance', enrolled:180, rating:4.6, listed:true, featured:false, price:'₹35,000' },
  { id:'mp4', title:'Digital Transformation Leadership', provider:'fourward', duration:'10 weeks', format:'Blended', category:'Digital', enrolled:120, rating:4.5, listed:true, featured:false, price:'₹55,000' },
  { id:'mp5', title:'Women in Leadership', provider:'fourward', duration:'16 weeks', format:'Virtual', category:'DEI', enrolled:95, rating:4.7, listed:true, featured:false, price:'₹65,000' },
  { id:'mp6', title:'Data Analytics for Leaders', provider:'IIT-B Exec Ed', duration:'8 weeks', format:'Virtual', category:'Analytics', enrolled:0, rating:0, listed:false, featured:false, price:'₹40,000' },
];
function SAMarketplace() {
  const [listings, setListings] = React.useState(SA_MARKETPLACE_PROGRAMS.map(p=>({...p})));
  const [saved, setSaved] = React.useState({});
  function toggle(id, key) {
    setListings(prev => prev.map(p => p.id===id ? {...p,[key]:!p[key]} : p));
    setSaved(p=>({...p,[id+key]:true}));
    setTimeout(()=>setSaved(p=>({...p,[id+key]:false})),1500);
  }
  const listed = listings.filter(p=>p.listed);
  return (
    <div style={{ padding:24, display:'flex', flexDirection:'column', gap:16, overflowY:'auto', fontFamily:'Poppins,sans-serif' }}>
      <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:14 }}>
        {[['Listed Programs',listed.length,'#1C2551'],['Featured',listed.filter(p=>p.featured).length,'#f59e0b'],['Total Enrollments',listings.reduce((a,p)=>a+p.enrolled,0).toLocaleString(),'#EF4E24'],['Avg Rating',(listed.filter(p=>p.rating>0).reduce((a,p)=>a+p.rating,0)/listed.filter(p=>p.rating>0).length||0).toFixed(1),'#22c55e']].map(([l,v,c])=>(
          <div key={l} style={{ background:'#fff', borderRadius:12, border:'1px solid #EAECF4', padding:'16px 18px', boxShadow:'0 1px 4px rgba(28,37,81,0.06)' }}>
            <div style={{ fontSize:11, color:'#8b90a7', marginBottom:5 }}>{l}</div>
            <div style={{ fontSize:26, fontWeight:800, color:c }}>{v}</div>
          </div>
        ))}
      </div>
      <div style={{ background:'#fff', borderRadius:12, border:'1px solid #EAECF4', overflow:'hidden', boxShadow:'0 1px 4px rgba(28,37,81,0.06)' }}>
        <div style={{ padding:'14px 20px', borderBottom:'1px solid #EAECF4', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
          <div style={{ fontSize:14, fontWeight:700, color:'#1C2551' }}>Program Catalogue</div>
          <button style={{ padding:'8px 16px', background:'#1C2551', border:'none', borderRadius:8, fontSize:12, fontWeight:700, color:'#fff', cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>+ Add Program</button>
        </div>
        <table style={{ width:'100%', borderCollapse:'collapse' }}>
          <thead><tr style={{ background:'#F5F7FB' }}>{['Program','Provider','Duration','Format','Category','Enrollments','Rating','Price','Listed','Featured','Actions'].map(h=><th key={h} style={{ padding:'10px 14px', fontSize:10, fontWeight:700, color:'#8b90a7', textAlign:'left', whiteSpace:'nowrap' }}>{h}</th>)}</tr></thead>
          <tbody>
            {listings.map((p,i)=>(
              <tr key={i} style={{ borderTop:'1px solid #F5F7FB', opacity:p.listed?1:0.6 }}>
                <td style={{ padding:'12px 14px' }}>
                  <div style={{ fontSize:12, fontWeight:700, color:'#1C2551' }}>{p.title}</div>
                </td>
                <td style={{ padding:'12px 14px', fontSize:11, color:'#8b90a7' }}>{p.provider}</td>
                <td style={{ padding:'12px 14px', fontSize:11, color:'#1C2551' }}>{p.duration}</td>
                <td style={{ padding:'12px 14px' }}><span style={{ fontSize:9, background:'rgba(28,37,81,0.07)', color:'#1C2551', borderRadius:10, padding:'3px 8px', fontWeight:700 }}>{p.format.toUpperCase()}</span></td>
                <td style={{ padding:'12px 14px', fontSize:11, color:'#8b90a7' }}>{p.category}</td>
                <td style={{ padding:'12px 14px', fontSize:12, fontWeight:700, color:'#EF4E24' }}>{p.enrolled.toLocaleString()}</td>
                <td style={{ padding:'12px 14px', fontSize:12, fontWeight:700, color:'#22c55e' }}>{p.rating>0?'★ '+p.rating:'—'}</td>
                <td style={{ padding:'12px 14px', fontSize:12, fontWeight:600, color:'#1C2551' }}>{p.price}</td>
                <td style={{ padding:'12px 14px' }}>
                  <div onClick={()=>toggle(p.id,'listed')} style={{ width:36,height:20,borderRadius:10,background:p.listed?'#22c55e':'#D0D3E0',cursor:'pointer',position:'relative',transition:'background 0.2s' }}>
                    <div style={{ position:'absolute',top:2,left:p.listed?18:2,width:16,height:16,borderRadius:'50%',background:'#fff',transition:'left 0.2s',boxShadow:'0 1px 3px rgba(0,0,0,0.15)' }}></div>
                  </div>
                </td>
                <td style={{ padding:'12px 14px' }}>
                  <div onClick={()=>p.listed&&toggle(p.id,'featured')} style={{ width:36,height:20,borderRadius:10,background:p.featured?'#f59e0b':'#D0D3E0',cursor:p.listed?'pointer':'not-allowed',position:'relative',transition:'background 0.2s',opacity:p.listed?1:0.4 }}>
                    <div style={{ position:'absolute',top:2,left:p.featured?18:2,width:16,height:16,borderRadius:'50%',background:'#fff',transition:'left 0.2s',boxShadow:'0 1px 3px rgba(0,0,0,0.15)' }}></div>
                  </div>
                </td>
                <td style={{ padding:'12px 14px' }}>
                  <div style={{ display:'flex', gap:5 }}>
                    <button style={{ padding:'4px 9px', background:'#F5F7FB', border:'1px solid #EAECF4', borderRadius:6, fontSize:10, fontWeight:600, color:'#1C2551', cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>Edit</button>
                    <button style={{ padding:'4px 9px', background:'rgba(239,78,36,0.06)', border:'1px solid rgba(239,78,36,0.2)', borderRadius:6, fontSize:10, fontWeight:600, color:'#EF4E24', cursor:'pointer', fontFamily:'Poppins,sans-serif' }}>Remove</button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

