// ─── Settings Page (full main-area view) ─────────────────────────────────────
function SettingsPage({ persona }) {
  const [tab, setTab] = React.useState('account');
  const [saved, setSaved] = React.useState(false);
  const [notifs, setNotifs] = React.useState({ email:true, push:true, sms:false, deadlines:true, feedback:true, sessions:true, reports:false });
  const [platform, setPlatform] = React.useState({ maintenance:false, sessionTimeout:30, mfaRequired:false, passwordExpiry:90 });
  const nav = NAV_CONFIG[persona];
  const isSA = persona === 'superAdmin';
  const isPM = persona === 'programManager';
  const TABS = [
    { id:'account',       label:'My Account',    icon:'◎' },
    { id:'notifications', label:'Notifications', icon:'🔔' },
    ...(isSA ? [{ id:'platform', label:'Platform', icon:'◈' },{ id:'security', label:'Security', icon:'◆' },{ id:'api', label:'API & Keys', icon:'✦' },{ id:'features', label:'Feature Flags', icon:'⬡' },{ id:'storage', label:'Storage', icon:'▦' },{ id:'localization', label:'Localization', icon:'◎' }] : []),
    ...((isSA || isPM) ? [{ id:'brandkit', label:'Brand Kit', icon:'🎨' }] : []),
    { id:'appearance',    label:'Appearance',    icon:'◇' },
  ];
  function save() { setSaved(true); setTimeout(()=>setSaved(false), 2200); }
  return (
    <div style={{ padding:24, fontFamily:'Poppins,sans-serif', display:'flex', flexDirection:'column', gap:0, minHeight:'100%', boxSizing:'border-box', background:'#F5F7FB' }}>
      <div style={{ background:'#fff', borderRadius:14, border:'1px solid #EAECF4', overflow:'hidden', display:'flex', flexDirection:'column', boxShadow:'0 1px 4px rgba(28,37,81,0.07)' }}>
        {/* Tab header bar */}
        <div style={{ display:'flex', borderBottom:'1px solid #EAECF4', background:'#FAFBFC', overflowX:'auto', scrollbarWidth:'none' }}>
          {TABS.map(t => (
            <button key={t.id} onClick={() => setTab(t.id)} style={{ display:'flex', alignItems:'center', gap:7, padding:'14px 20px', border:'none', background:'transparent', cursor:'pointer', fontFamily:'Poppins,sans-serif', borderBottom:tab===t.id?'2.5px solid #EF4E24':'2.5px solid transparent', marginBottom:'-1px', flexShrink:0 }}>
              <span style={{ fontSize:14, color:tab===t.id?'#EF4E24':'#8b90a7' }}>{t.icon}</span>
              <span style={{ fontSize:13, fontWeight:tab===t.id?700:400, color:tab===t.id?'#EF4E24':'#8b90a7', whiteSpace:'nowrap' }}>{t.label}</span>
            </button>
          ))}
        </div>
        {/* Content */}
        <div style={{ padding:'28px 32px', display:'flex', flexDirection:'column', gap:16 }}>
          {tab==='account'       && <AccountTab persona={persona} nav={nav} />}
          {tab==='notifications' && <NotificationsTab notifs={notifs} setNotifs={setNotifs} />}
          {tab==='platform'      && isSA && <PlatformTab platform={platform} setPlatform={setPlatform} />}
          {tab==='security'      && isSA && <SecurityTab />}
          {tab==='api'           && isSA && <ApiKeysTab />}
          {tab==='brandkit'     && (isSA||isPM) && <BrandKitTab />}
          {tab==='features'     && isSA && <FeaturesTab />}
          {tab==='storage'      && isSA && <StorageTab />}
          {tab==='localization' && isSA && <LocalizationTab />}
          {tab==='appearance'    && <AppearanceTab />}
        </div>
        {/* Footer */}
        <div style={{ padding:'16px 32px', borderTop:'1px solid #EAECF4', display:'flex', justifyContent:'space-between', alignItems:'center', background:'#FAFBFC' }}>
          <div style={{ fontSize:11, color:'#8b90a7' }}>Changes apply immediately after saving.</div>
          <button onClick={save} style={{ padding:'10px 28px', border:'none', borderRadius:9, background:saved?'#22c55e':'#EF4E24', cursor:'pointer', fontSize:13, fontWeight:700, color:'#fff', fontFamily:'Poppins,sans-serif', transition:'background 0.2s', minWidth:130 }}>
            {saved ? '✓ Saved!' : 'Save Changes'}
          </button>
        </div>
      </div>
    </div>
  );
}

function PersonaSwitcher({ persona, onSwitch, mode, onModeSwitch, onLogout }) {
  const [open, setOpen] = React.useState(false);
  const [pos, setPos] = React.useState(null);
  const dragging = React.useRef(false);
  const moved = React.useRef(false);
  const dragOffset = React.useRef({ x:0, y:0 });
  const personas = Object.keys(PERSONA_META);
  const current = PERSONA_META[persona];

  function handleMouseDown(e) {
    dragging.current = true;
    moved.current = false;
    const rect = e.currentTarget.parentNode.getBoundingClientRect();
    dragOffset.current = { x: e.clientX - rect.left, y: e.clientY - rect.top };
    e.preventDefault();
    function onMove(ev) {
      if (!dragging.current) return;
      moved.current = true;
      setPos({
        left: Math.max(8, Math.min(ev.clientX - dragOffset.current.x, window.innerWidth - 88)),
        top:  Math.max(8, Math.min(ev.clientY - dragOffset.current.y, window.innerHeight - 88)),
      });
    }
    function onUp() {
      dragging.current = false;
      window.removeEventListener('mousemove', onMove);
      window.removeEventListener('mouseup', onUp);
    }
    window.addEventListener('mousemove', onMove);
    window.addEventListener('mouseup', onUp);
  }

  function handleClick() {
    if (!moved.current) setOpen(o => !o);
    moved.current = false;
  }

  const wrapStyle = pos
    ? { position:'fixed', left:pos.left, top:pos.top, zIndex:9999 }
    : { position:'fixed', bottom:28, right:28, zIndex:9999 };

  const menuStyle = pos
    ? { position:'absolute', top: pos.top > window.innerHeight/2 ? 'auto' : 60, bottom: pos.top > window.innerHeight/2 ? 60 : 'auto', left: pos.left > window.innerWidth/2 ? 'auto' : 0, right: pos.left > window.innerWidth/2 ? 0 : 'auto', background:'#fff', borderRadius:14, boxShadow:'0 8px 40px rgba(28,37,81,0.18)', border:'1px solid #EAECF4', overflow:'hidden', minWidth:220 }
    : { position:'absolute', bottom:60, right:0, background:'#fff', borderRadius:14, boxShadow:'0 8px 40px rgba(28,37,81,0.18)', border:'1px solid #EAECF4', overflow:'hidden', minWidth:220 };

  return (
    <div style={wrapStyle}>
      {open && (
        <div style={menuStyle}>
          <div style={{ padding:'12px 16px', borderBottom:'1px solid #EAECF4' }}>
            <div style={{ fontSize:10, fontWeight:700, color:'#8b90a7', letterSpacing:1, marginBottom:8 }}>VIEW MODE</div>
            <div style={{ display:'flex', gap:6 }}>
              {['web','mobile'].map(m => (
                <button key={m} onClick={() => onModeSwitch(m)} style={{ flex:1, padding:'7px 0', border:`1.5px solid ${mode===m?'#EF4E24':'#EAECF4'}`, borderRadius:8, background:mode===m?'rgba(239,78,36,0.08)':'#fff', color:mode===m?'#EF4E24':'#8b90a7', fontSize:11, fontWeight:mode===m?700:400, cursor:'pointer', fontFamily:'Poppins,sans-serif', display:'flex', alignItems:'center', justifyContent:'center', gap:5 }}>
                  <span>{m==='web'?'💻':'📱'}</span>{m==='web'?'Web':'Mobile'}
                </button>
              ))}
            </div>
          </div>
          <div style={{ padding:'10px 16px', fontSize:10, fontWeight:700, color:'#8b90a7', letterSpacing:1, borderBottom:'1px solid #EAECF4' }}>SWITCH PERSONA</div>
          {personas.map(p => {
            const meta = PERSONA_META[p];
            return (
              <button key={p} onClick={() => { onSwitch(p); setOpen(false); }}
                style={{ display:'flex', alignItems:'center', gap:12, padding:'12px 16px', width:'100%', border:'none', background:p===persona?'rgba(239,78,36,0.05)':'#fff', cursor:'pointer', fontFamily:'Poppins,sans-serif', borderBottom:'1px solid #EAECF4' }}>
                <div style={{ width:28, height:28, borderRadius:'50%', background:meta.color, color:'#fff', fontWeight:800, fontSize:10, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>{meta.abbr}</div>
                <div style={{ textAlign:'left', flex:1 }}>
                  <div style={{ fontSize:12, fontWeight:600, color:'#1C2551' }}>{meta.label}</div>
                </div>
                {p === persona && <span style={{ marginLeft:'auto', color:'#EF4E24', fontSize:14 }}>✓</span>}
              </button>
            );
          })}
          <button onClick={() => { onLogout && onLogout(); setOpen(false); }} style={{ display:'flex', alignItems:'center', gap:12, padding:'12px 16px', width:'100%', border:'none', background:'rgba(239,78,36,0.04)', cursor:'pointer', fontFamily:'Poppins,sans-serif', borderTop:'1px solid #EAECF4' }}>
            <div style={{ width:28, height:28, borderRadius:'50%', background:'rgba(239,78,36,0.12)', color:'#EF4E24', fontSize:14, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>⎋</div>
            <div style={{ textAlign:'left', flex:1 }}><div style={{ fontSize:12, fontWeight:700, color:'#EF4E24' }}>Log Out</div></div>
          </button>
        </div>
      )}
      <button onClick={handleClick} onMouseDown={handleMouseDown}
        style={{ width:52, height:52, borderRadius:'50%', background:'#EF4E24', border:'none', cursor:'grab', boxShadow:'0 4px 20px rgba(239,78,36,0.4)', display:'flex', alignItems:'center', justifyContent:'center', flexDirection:'column', gap:2, userSelect:'none' }}>
        <div style={{ width:18, height:2, background:'#fff', borderRadius:2 }}></div>
        <div style={{ width:14, height:2, background:'rgba(255,255,255,0.7)', borderRadius:2 }}></div>
        <div style={{ width:18, height:2, background:'#fff', borderRadius:2 }}></div>
      </button>
      <div style={{ textAlign:'center', marginTop:6 }}>
        <span style={{ background:'#1C2551', color:'#fff', borderRadius:20, padding:'3px 10px', fontSize:9, fontWeight:700 }}>{current.abbr}</span>
      </div>
    </div>
  );
}

// ─── Root App ─────────────────────────────────────────────────────────────────
function App() {
  // Guard against stale localStorage from older builds
  (function() {
    try {
      const sp = localStorage.getItem('xa_persona');
      if (sp && !DEFAULT_PAGE[sp]) {
        ['xa_persona','xa_page','xa_logged_in','xa_prog_id','xa_fac_prog_id','xa_mode'].forEach(function(k){ localStorage.removeItem(k); });
      }
    } catch(e) {}
  })();
  const [loggedIn, setLoggedIn] = React.useState(() => !!localStorage.getItem('xa_logged_in'));
  const [selectedProgId, setSelectedProgId] = React.useState(() => localStorage.getItem('xa_prog_id') || 'prog1');
  const [selectedFacProgId, setSelectedFacProgId] = React.useState(() => localStorage.getItem('xa_fac_prog_id') || 'fprog1');
  const [persona, setPersona] = React.useState(() => localStorage.getItem('xa_persona') || 'participant');
  const [page, setPage] = React.useState(() => {
    const saved = localStorage.getItem('xa_page');
    const savedPersona = localStorage.getItem('xa_persona') || 'participant';
    return saved || DEFAULT_PAGE[savedPersona];
  });

  const [mode, setMode] = React.useState(() => localStorage.getItem('xa_mode') || 'web');
  const [orgFilter, setOrgFilter] = React.useState('All Orgs');
  const [statDetail, setStatDetail] = React.useState(null);
  React.useEffect(() => {
    function handler(e) { setStatDetail(e.detail); }
    window.addEventListener('xa-stat-detail', handler);
    return () => window.removeEventListener('xa-stat-detail', handler);
  }, []);

  function switchMode(m) { setMode(m); localStorage.setItem('xa_mode', m); }

  const selectedProg = persona === 'participant' ? (PARTICIPANT_PROGRAMS.find(p => p.id === selectedProgId) || PARTICIPANT_PROGRAMS[0]) : null;
  function changeProgram(id) { setSelectedProgId(id); localStorage.setItem('xa_prog_id', id); }
  const selectedFacProg = persona === 'faculty' ? (FACULTY_PROGRAMS.find(p => p.id === selectedFacProgId) || FACULTY_PROGRAMS[0]) : null;
  function changeFacProgram(id) { setSelectedFacProgId(id); localStorage.setItem('xa_fac_prog_id', id); }
  const activeProgram = persona === 'participant' ? selectedProg : persona === 'faculty' ? selectedFacProg : null;
  const activePrograms = persona === 'participant' ? PARTICIPANT_PROGRAMS : persona === 'faculty' ? FACULTY_PROGRAMS : null;
  const activeChangeProgram = persona === 'faculty' ? changeFacProgram : changeProgram;

  function login(p) {
    const np = DEFAULT_PAGE[p];
    setPersona(p); setPage(np); setLoggedIn(true);
    localStorage.setItem('xa_logged_in', '1');
    localStorage.setItem('xa_persona', p);
    localStorage.setItem('xa_page', np);
  }
  function logout() { setLoggedIn(false); localStorage.removeItem('xa_logged_in'); }

  function switchPersona(p) {
    setPersona(p);
    const newPage = DEFAULT_PAGE[p];
    setPage(newPage);
    localStorage.setItem('xa_persona', p);
    localStorage.setItem('xa_page', newPage);
  }

  function navigate(p) {
    setPage(p);
    localStorage.setItem('xa_page', p);
  }

  if (!loggedIn) return <OpenProgramsPage onLogin={login} />;

  return (
    <div style={{ display:'flex', height:'100vh', overflow:'hidden', fontFamily:"'Poppins', sans-serif" }}>
      {mode === 'web' ? (
        <>
          <Sidebar persona={persona} activePage={page} onNavigate={navigate} program={selectedProg} />
          <div style={{ flex:1, display:'flex', flexDirection:'column', overflow:'hidden' }}>
            <Header title={getPageTitle(page)} subtitle={getPageSub(page)} persona={persona} onProfileClick={() => navigate('profile')} orgFilter={orgFilter} onOrgChange={setOrgFilter} programs={activePrograms} selectedProg={activeProgram} onProgChange={activeChangeProgram} onSettingsClick={() => navigate('settings')} />
            <main style={{ flex:1, overflowY:'auto', background:'#F5F7FB' }}>
              {renderPage(page, persona, orgFilter, activeProgram, navigate)}
            </main>
          </div>
        </>
      ) : (
        <div style={{ flex:1, background:'#d8d5cf', overflow:'auto' }}>
          <div style={{ minHeight:'100%', display:'flex', alignItems:'center', justifyContent:'center', padding:'48px 24px', boxSizing:'border-box' }}>
            <PhoneFrame>
              <MobileApp persona={persona} />
            </PhoneFrame>
          </div>
        </div>
      )}
      <PersonaSwitcher persona={persona} onSwitch={switchPersona} mode={mode} onModeSwitch={switchMode} onLogout={logout} />
      {mode === 'web' && <StatDetailOverlay data={statDetail} onClose={()=>setStatDetail(null)} />}
    </div>
  );
}

// Expose for DC mounting
window.XALmsApp = App;
